export const chunk5: Poem[] = [
  { id: 561, title: "双调·水仙子·咏江南",
    author: "张养浩",
    dynasty: "元",
    category: "元",
    summary: "一江烟水照晴岚两岸人家接画檐芰荷丛一段秋光淡看沙鸥舞再三卷香风十里珠帘画船儿天边至酒旗儿风外飐爱杀江南",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "双调·水仙子·咏江南", original: `
一江烟水照晴岚，
两岸人家接画檐。
芰荷丛一段秋光淡。
看沙鸥舞再三，
卷香风十里珠帘。
画船儿天边至，
酒旗儿风外飐。
爱杀江南
`, translation: `一江清澈的烟水映照着雨后山间的云气，两岸人家的屋檐像画一样连成一片。丛丛的菱叶荷花铺展开来，像是秋天里一段淡淡的光景。几只白色的沙鸥在水面上飞舞，一阵又一阵地卷起；桂花的香气随风飘来，十里长街都闻到了香味。漂亮的画船从天边慢慢驶来，酒馆的旗子在风中飘动。真是让人太喜爱这江南了！`, interpretation: `这首小令写于元朝，那时候许多文人不再追求做官，转而寄情于山水之间，张养浩就是其中一位。他晚年回到家乡，看惯了北方的萧瑟，便格外向往江南的温柔。全曲像一幅长卷慢慢展开：先写江水和远山，再写人家和荷塘，接着是飞舞的沙鸥、飘来的花香，最后画船和酒旗出场，把江南的热闹与诗意一笔点出。短短几句，没有一个'美'字，却处处是美，这正是它高明的地方。'酒旗儿风外飐'一句尤其生动，让人仿佛闻到风中酒香。这首曲子后来常被用来形容江南，成为元曲写景的佳作。` }] },
  { id: 562, title: "送岳季方还京",
    author: "郭登",
    dynasty: "明",
    category: "明",
    summary: "登高欲上最高层，脚底昆仑未足登，直待身轻似黄蝶，乘风飞过万重山",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "送岳季方还京", original: `
登高欲上最高层，
脚底昆仑未足登，
直待身轻似黄蝶，
乘风飞过万重山
`, translation: `我爬上高山，想要登上最高的那一层。可惜啊，脚底下的昆仑山都还没爬完呢。我要一直等到身体变得很轻很轻，像黄色的蝴蝶一样，然后借着风的力量，飞过成千上万座山。`, interpretation: `这首诗是明代郭登送别朋友岳季方时写的。诗中充满了对朋友远行的美好祝愿和豪迈想象。诗人借登山来比喻人生，目标越高，路途越远，但他不以为苦，反而想象有朝一日能身轻如蝶，乘风飞越万山，这种浪漫夸张的写法让小读者也能感受到古人送别诗中的壮志豪情。'乘风飞过万重山'一句想象奇特，气魄宏大，是整首诗最精彩的结句，也常被后人引用来形容克服困难、勇往直前的志向。` }] },
  { id: 563, title: "就义诗",
    author: "杨继盛",
    dynasty: "明",
    category: "明",
    summary: "浩气还太虚，丹心照千古，平生未报国，留作忠魂补",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "就义诗", original: `
浩气还太虚，
丹心照千古，
平生未报国，
留作忠魂补
`, translation: `我这一身浩然正气将回归天地之间，我赤诚的忠心能光照千秋万代。这一辈子还没来得及报答国家，就让我留下这颗忠魂来继续弥补吧。`, interpretation: `这首诗是明代忠臣杨继盛临刑前写下的。1556年，他因为弹劾奸臣严嵩而被害，年仅四十岁。诗中“浩气”“丹心”“忠魂”三个词特别有力量，写出了一个正直的人即使牺牲，也要把忠心留在人间的决心。这首诗最大的特色是短短二十个字，却写得气势磅礴，像一声豪迈的呐喊，让人读来热血沸腾。"浩气还太虚"一句尤其震撼，后来常被用来形容爱国志士的伟大气节，连电视剧里英雄就义时都爱引用呢！` }] },
  { id: 564, title: "春日",
    author: "唐寅",
    dynasty: "明",
    category: "明",
    summary: "残睡未醒人未起，半钩帘幕怕春寒，阶前一夜东风起，花落花开独自看",
    tags: "明,写景",
    color: "#ef4444",
    sections:[    { id: 1, title: "春日", original: `
残睡未醒人未起，
半钩帘幕怕春寒，
阶前一夜东风起，
花落花开独自看
`, translation: `早上人还赖床没睡醒，窗帘只挂一半，怕外面的春风吹进来太冷。昨夜里台阶前忽然刮起东风，催得花瓣落花又花开，只有我一个人静静地看着。`, interpretation: `这是明代才子唐伯虎写的小诗，很有生活趣味。春天来了，他却窝在被窝里不想起，娇娇气气地只挂半幅帘子挡风。夜里东风悄悄吹过台阶，一夜之间花开花落，满院子只有他一个人欣赏。诗里没有大道理，却把春天清晨那种慵懒、又有点小敏感的心情写得特别可爱。尤其是'半钩帘幕怕春寒'，一个小动作就把人怕冷又爱春的样子画出来了。整首诗短短四句，像一幅淡淡的水墨小画，让人读了也想赖在春天里多睡一会儿。` }] },
  { id: 565, title: "竹枝词",
    author: "袁宏道",
    dynasty: "明",
    category: "明",
    summary: "雪里山茶取次红，白头孀妇哭春风，自从貂虎横行后，十室金钱九室空",
    tags: "明,民生",
    color: "#ef4444",
    sections:[    { id: 1, title: "竹枝词", original: `
雪里山茶取次红，
白头孀妇哭春风，
自从貂虎横行后，
十室金钱九室空
`, translation: `雪天里山茶花一朵朵地红艳绽放，无人欣赏；白发苍苍的寡妇独自在寒风中悲伤哭泣。自从那些贪官酷吏像貂狼猛虎一样横行霸道以来，十户人家里的钱就有九户被搜刮一空。`, interpretation: `这首诗写于明朝末年，当时官吏如狼似虎，百姓苦不堪言。诗人袁宏道巧妙地以雪中红艳的山茶花做对比，繁华依旧，却无人有心情欣赏。一位白发寡妇在春风中哭泣，为什么？因为苛政猛于虎，十户人家九户空，连最无助的老人也难逃劫难。诗人用山茶花盛开与民不聊生的反差，控诉了贪官污吏对百姓的残酷剥削。语言质朴，情感真挚，短短四句便勾勒出一幅凄凉的晚明民生图，是明代现实主义诗歌中的佳作。` }] },
  { id: 566, title: "江行",
    author: "何景明",
    dynasty: "明",
    category: "明",
    summary: "寒江日暮浪花催，倦客登临首重回，孤猿啼处月徘徊，一点渔灯出夜来",
    tags: "明,写景",
    color: "#ef4444",
    sections:[    { id: 1, title: "江行", original: `
寒江日暮浪花催，
倦客登临首重回，
孤猿啼处月徘徊，
一点渔灯出夜来
`, translation: `傍晚的江面上寒气逼人,浪花一波推着一波。疲惫的旅人登上船头,忍不住一次次回头张望。孤零零的猿猴在岸边啼叫,月亮听到也忍不住在天上走来走去、停下脚步。夜色越来越深,远远的地方,有一盏渔火亮了起来,像是夜空中的一颗小星星。`, interpretation: `这是明代诗人何景明写的一首旅途小诗。何景明是明代"前七子"之一,主张诗歌要写出真情实感。诗里描绘了傍晚时分,诗人乘船沿江而行时的所见所感:寒冷的江水、翻滚的浪花、岸边哀啼的猿猴,还有远处一点亮起的渔灯。短短四句,写出了旅途的孤独和疲惫,也写出了夜色中那一盏渔灯带来的温暖和希望。诗中最妙的是最后一句"一点渔灯出夜来",一个"出"字让渔灯仿佛活了过来,像是特意来陪伴孤独的旅人。这首诗语言简练,画面感很强,让人读着读着就好像也坐在这艘小船上,在寒冷的江面上漂泊呢!` }] },
  { id: 567, title: "送戴式之归天台",
    author: "谢榛",
    dynasty: "明",
    category: "明",
    summary: "天涯倦客欲归迟，风雨登临一赋诗，黄叶满山人迹少，不堪重对菊花时",
    tags: "明,送别",
    color: "#ef4444",
    sections:[    { id: 1, title: "送戴式之归天台", original: `
天涯倦客欲归迟，
风雨登临一赋诗，
黄叶满山人迹少，
不堪重对菊花时
`, translation: `我漂泊天涯已经疲倦，想回家却又迟迟启程。顶风冒雨登上高山，写下这首诗。黄叶落满了整座山，路上几乎看不见行人。这种时候，我实在不忍心再去看那满山的菊花。`, interpretation: `这首诗写于明代，送别好友戴式之时。当时诗人谢榛四处漂泊，怀才不遇，心中满是疲惫与愁苦。诗中最妙的是'黄叶'和'菊花'两个意象：满山黄叶说明已是深秋，菊花盛开本该让人欢喜，可诗人却'不堪重对'——因为菊花让他想起离别的朋友，想起自己回不去的家乡。短短四句，没有一个'愁'字，却处处是愁。风雨登高的孤独、黄叶遍野的萧瑟，让这首小诗成为明代送别诗中的佳作，那份'欲归迟'的犹豫，至今读来仍让人动容。` }] },
  { id: 568, title: "戏题放翁诗后",
    author: "赵翼",
    dynasty: "清",
    category: "清",
    summary: "天为诗人养性灵，龙蛇风雨笔纵横，何须更写闲花草，开到梅花诗自成",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "戏题放翁诗后", original: `
天为诗人养性灵，
龙蛇风雨笔纵横，
何须更写闲花草，
开到梅花诗自成
`, translation: `老天爷专门为诗人养着一份灵性，让他拿起笔来风雨般龙飞凤舞、纵横驰骋。何必再去写那些无聊的闲花野草呢？等到梅花盛开的时候，好诗自然就写成了。`, interpretation: `这首诗写于清朝，是赵翼读了大诗人陆游（号放翁）的诗集后有感而发，专门题写在诗集后面的，所以叫“戏题”。当时赵翼主张诗歌要有真性情，要写大题材、大气象，不该只在花花草草里打转。诗中“龙蛇”“风雨”都是形容笔力雄健，气势磅礴；最后点出“梅花”这一高洁意象，象征真正的诗人只要胸中有丘壑，灵感一到，好诗自然天成。这首诗短小精悍，既是夸赞陆游，也是赵翼自己诗学主张的宣言，影响了后来不少诗人。` }] },
  { id: 569, title: "论诗五首·其一",
    author: "赵翼",
    dynasty: "清",
    category: "清",
    summary: "满眼生机转化钧，天工人巧日争新，预支五百年新意，到了千年又觉陈",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "论诗五首·其一", original: `
满眼生机转化钧，
天工人巧日争新，
预支五百年新意，
到了千年又觉陈
`, translation: `满眼都是蓬勃的生机，宇宙像一台大转盘，把万事万物不停地推动变化；自然的创造和人的巧妙心思，一天比一天更加新鲜。哪怕你提前用上了五百年的新创意，等到一千年的时候再看，也会觉得已经过时啦。`, interpretation: `这首诗写于清代，当时文坛上模仿古人、堆砌典故的风气很重，赵翼特别看不惯，就写诗来反对。他在诗里说：大自然和人类都在不断创新，今天觉得新鲜的东西，过几百年就老土了，所以写诗也要有自己新想法，不能老跟着古人走。这首诗最有名的是后两句，后来变成了"预支五百年新意，到了千年又觉陈"，常被人们用来鼓励创新，不要被老规矩绑住手脚。` }] },
  { id: 570, title: "湖上杂诗",
    author: "袁枚",
    dynasty: "清",
    category: "清",
    summary: "凤岭高登演武台，排空石阵阵云开，英雄立马起沙陀，奈此朱梁跋扈何",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "湖上杂诗", original: `
凤岭高登演武台，
排空石阵阵云开，
英雄立马起沙陀，
奈此朱梁跋扈何
`, translation: `登上高高的演武台，凤岭就在眼前。排排巨石直指天空，阵云忽然散开。英雄骑着战马冲上沙陀，可是面对这样飞扬跋扈的朱梁，又能怎么办呢？`, interpretation: `这首诗写于清朝，袁枚借登演武台眺望，回忆古代的战场风云。诗中的凤岭、演武台、沙陀、朱梁，都是历史上的真实地名和人物，把读者带回金戈铁马的年代。短短四句，气势磅礴，'排空石阵阵云开'特别有画面感，仿佛能看见巨石林立、云开雾散。结尾用一个'奈此朱梁跋扈何'，既写出了英雄的无奈，也暗含对历史兴亡的感慨，读起来让人心潮澎湃。` }] },
  { id: 571, title: "山中",
    author: "袁枚",
    dynasty: "清",
    category: "清",
    summary: "千山万山云雾堆，一声何处鹤飞来，停琴欲待仙人去，又见月出西山隈",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "山中", original: `
千山万山云雾堆，
一声何处鹤飞来，
停琴欲待仙人去，
又见月出西山隈
`, translation: `云雾堆满了千万座山，一声鹤叫不知从哪儿传来。我停下弹琴，想等着仙人一起飞走，却又看见月亮从西边的山弯里升起来了。`, interpretation: `这首诗出自清代诗人袁枚的《山中》，写的是山里的悠闲时光。袁枚是清代的大才子，喜欢游山玩水、写下随性的小诗。这首诗里最有趣的地方是“云雾堆”三个字，把山里的云写得好像能堆起来一样，又厚又满，让人觉得很可爱。忽然一声鹤叫，诗人就想跟着仙人飞走，这种天马行空的想象特别有童趣。整首诗短短四句，却有云、有鹤、有琴、有月，像一幅慢慢展开的山中夜景图，写出了古人追求自由自在的心境。这种“想当仙人”的浪漫想法，后来也影响了很多诗人和画家。` }] },
  { id: 572, title: "山行",
    author: "姚鼐",
    dynasty: "清",
    category: "清",
    summary: "布谷飞飞劝早耕，舂锄扑扑趁春晴，千层石树通行路，一帶山田放水声",
    tags: "清,田园",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "山行", original: `
布谷飞飞劝早耕，
舂锄扑扑趁春晴，
千层石树通行路，
一帶山田放水声
`, translation: `布谷鸟在田头飞上飞下地叫，催着农人快快耕地。农夫举起舂锄一下一下地拍打着泥土，正好趁着这晴朗的春天。走过由石头和树木堆成的层层小路，听见山田里哗哗的水声，正准备引水灌田。`, interpretation: `这首诗写于清朝，描绘的是春天农忙的田园景象。诗中最有意思的意象是“布谷鸟”——古人觉得它的叫声像在喊“快快播谷”，所以叫它布谷鸟，一开篇就活了整幅画。农夫趁着春光、踩着石路、听着水声，画面有声有色，一派生机。姚鼐是桐城派大家，但写起田园诗来却特别亲切自然，让小朋友也能感受到乡村的热闹和美好。这种清新朴素的风格，后来许多写田园诗的人都向他学习呢！` }] },
  { id: 573, title: "山中留客",
    author: "张旭",
    dynasty: "唐",
    category: "唐",
    summary: "山光物态弄春晖，莫为轻阴便拟归，纵使晴明无雨色，入云深处亦沾衣",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "山中留客", original: `
山光物态弄春晖，
莫为轻阴便拟归，
纵使晴明无雨色，
入云深处亦沾衣
`, translation: `山中的阳光和万物都在春天的光辉里嬉戏玩耍，别因为天有点阴就打算回家。就算天气晴朗没有下雨，走进云雾缭绕的深山里，衣服也会被打湿的。`, interpretation: `这首诗是唐代书法家张旭写的，说的是主人挽留客人的情景。背景是朋友来访，遇到天阴，客人想走，主人便写下这首诗劝他留下。诗中'山光物态'是核心意象，描绘了春天山林里阳光万物活泼可爱的样子。最妙的是最后两句——晴天进山，衣服也会被云雾打湿——既说透了山中的真实情况，又藏着小惊喜：云雾沾衣不正说明山中景色如仙境吗？这种劝客的方式既贴心又有趣，后人常用'沾衣欲湿杏花雨'的意境来描写春山之美，这首诗可以说是它的老前辈啦！` }] },
  { id: 574, title: "桃花溪",
    author: "张旭",
    dynasty: "唐",
    category: "唐",
    summary: "隐隐飞桥隔野烟，石矶西畔问渔船，桃花尽日随流水，洞在清溪何处边",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "桃花溪", original: `
隐隐飞桥隔野烟，
石矶西畔问渔船，
桃花尽日随流水，
洞在清溪何处边
`, translation: `远远望去，一座高高的桥在田野的雾气中若隐若现。我站在石矶西边，向打鱼的小船打听消息。桃花花瓣一整天都随着溪水漂流而去。那个传说中的桃源洞口，究竟在这条清澈溪水的哪一边呢？`, interpretation: `这首诗写于唐代，那时很多人向往陶渊明笔下的世外桃源。张旭以书法狂草闻名，写诗也充满画意。他借眼前桃花随溪水漂流的景象，把陶渊明《桃花源记》的故事悄悄藏在诗里。短短四句，像一幅水墨画，又像一个谜语，让人忍不住想去寻找那片世外仙境。后来人们常用'桃花源'来比喻心中向往的美好地方，这首诗正是把这种向往写得最美的一首之一。` }] },
  { id: 575, title: "边词",
    author: "张敬忠",
    dynasty: "唐",
    category: "唐",
    summary: "五原春色旧来迟，二月垂杨未挂丝，即今河畔冰开日，正是长安花落时",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "边词", original: `
五原春色旧来迟，
二月垂杨未挂丝，
即今河畔冰开日，
正是长安花落时
`, translation: `五原的春天向来来得晚，二月里垂杨的枝条还没抽出新绿的丝带。就在河边的冰雪刚刚融化的今天啊，长安城里却已经是落花飘飞的暮春时节了。`, interpretation: `这首诗写于盛唐时期，张敬忠曾任西北边关将领，五原在今内蒙古一带，是唐朝的边防要地。那时候的诗人喜欢写边塞题材，这首小诗却别具一格——它不写战火烽烟，而写春天。诗人抓住一个有趣的对比：同一时间，边塞冰雪才化，长安却已落花满地。"未挂丝"三个字特别生动，柳枝还没发芽，像没系上丝带一样。短短四句，把边塞的荒寒和长安的繁华轻轻一比，让人感受到戍边将士对家乡的思念。这种"两地同时不同景"的写法，后来成了边塞诗的经典手法，也为许多送别诗所借鉴。` }] },
  { id: 577, title: "河湟旧卒",
    author: "张乔",
    dynasty: "唐",
    category: "唐",
    summary: "少年随将讨河湟，头白时清返故乡，十万汉军零落尽，独吹边曲向残阳",
    tags: "唐,边塞",
    color: "#f59e0b",
    sections:[    { id: 1, title: "河湟旧卒", original: `
少年随将讨河湟，
头白时清返故乡，
十万汉军零落尽，
独吹边曲向残阳
`, translation: `年轻的时候就跟着将军去攻打河湟地区的敌人，等到头发白了、天下太平了才回到家乡。当年那十万汉军将士，如今已经所剩无几，只剩下他一个人，独自吹着边塞的曲子，对着西下的夕阳。`, interpretation: `这首诗写于晚唐时期，当时边战频繁，许多士兵被征召去边疆作战，很多人再也没有回来。诗人张乔通过一位老兵的故事，表达了对战乱时代普通士兵悲惨命运的同情。诗中'残阳'这个意象特别动人，象征着老兵暮年的孤独和凄凉。短短四句诗，用'十万'和'独'的强烈对比，把历史的沧桑感写得震撼人心。'独吹边曲向残阳'这一句更是成为千古名句，让人读来心中酸楚，也让我们记住那些在历史洪流中默默消逝的小人物。` }] },
  { id: 578, title: "江楼感旧",
    author: "赵嘏",
    dynasty: "唐",
    category: "唐",
    summary: "独上江楼思渺然，月光如水水如天，同来望月人何处，风景依稀似去年",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "江楼感旧", original: `
独上江楼思渺然，
月光如水水如天，
同来望月人何处，
风景依稀似去年
`, translation: `我一个人登上江边的小楼，心里头空荡荡的，想得很远很远。月光洒下来，像水一样温柔；江水也像天空一样，闪着光。去年和我一起到这儿看月亮的那个人，现在不知道去了哪里。眼前的风景啊，还是去年的样子，可看风景的人却已经不在了。`, interpretation: `这首诗是唐代诗人赵嘏写的。有一年中秋节前后，他独自登上江边小楼，想起去年这时和朋友一起赏月的情景，于是写下了这首诗。诗中“月光如水水如天”一句非常有名，用水比月光，又用天比水，写出江上月夜的空灵之美，让人分不清哪里是天、哪里是水、哪里是月。整首诗最动人的是第三句“同来望月人何处”，朋友不在身边，只剩自己对着同样的月亮，短短七个字就让人心里酸酸的——这就是古人说的“物是人非”呀。后来很多人想表达“老朋友不见了”的心情，都会想起这一句。` }] },
  { id: 579, title: "闲居寄诸弟",
    author: "韦应物",
    dynasty: "唐",
    category: "唐",
    summary: "秋草生庭白露时，故园诸弟益相思，尽日高斋无一事，芭蕉叶上独题诗",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "闲居寄诸弟", original: `
秋草生庭白露时，
故园诸弟益相思，
尽日高斋无一事，
芭蕉叶上独题诗
`, translation: `秋天来了，院子里的青草上落着白白的露水。我忍不住更加想念家乡的弟弟们了。我一整天都在高高的书斋里没什么事做，就独自在芭蕉叶上写起诗来。`, interpretation: `这是唐代诗人韦应物写给弟弟们的诗。韦应物做过地方官，为人清廉正直，这首诗写于他闲居的时候。秋天本就是容易让人思念亲人的季节，诗人看着院子里的秋草白露，心里越发牵挂远方的兄弟们。整天没什么事做，就独自在芭蕉叶上写诗，芭蕉叶又大又绿，正好当纸用，画面特别有诗意。这种借景抒情、用身边小事寄托手足之情的手法，温馨又自然，让人读着也想起自己的兄弟姐妹呢。` }] },
  { id: 580, title: "山房春事",
    author: "岑参",
    dynasty: "唐",
    category: "唐",
    summary: "梁园日暮乱飞鸦，极目萧条三两家，庭树不知人去尽，春来还发旧时花",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "山房春事", original: `
梁园日暮乱飞鸦，
极目萧条三两家，
庭树不知人去尽，
春来还发旧时花
`, translation: `太阳落山了，梁园的乌鸦到处乱飞。抬头远望，曾经繁华的地方如今只剩下稀稀拉拉两三户人家。院子里的树啊，根本不知道人们都已经走光了，等到春天来了，还像以前一样开出了花。`, interpretation: `这首诗写于安史之乱以后，岑参路过汉代梁孝王建的梁园，触景生情。梁园曾经热闹非凡，如今却冷冷清清。诗人没有直接说“衰败”，而是让“庭树”当主角——树不懂人间沧桑，照样年年开花。这种“树无情，人有情”的写法特别巧妙，冷清的园子和热闹的春花形成对比，更让人心里发酸。后人常用“人去楼空”形容这种物是人非的感觉，这首诗就是最好的例子。` }] },
  { id: 581, title: "题大庾岭北驿",
    author: "宋之问",
    dynasty: "唐",
    category: "唐",
    summary: "阳月南飞雁，传闻至此回，我行殊未已，何日复归来，江静潮初落，林昏瘴不开，明朝望乡处，应见陇头梅",
    tags: "唐,思乡",
    color: "#f59e0b",
    sections:[    { id: 1, title: "题大庾岭北驿", original: `
阳月南飞雁，
传闻至此回，
我行殊未已，
何日复归来，
江静潮初落，
林昏瘴不开，
明朝望乡处，
应见陇头梅
`, translation: `十月份往南飞的大雁，听说飞到这座山就往回转了。我要去的路还远得很呢，什么时候才能再回来呀？江水安静，潮水刚刚落下；山林昏暗，瘴气散不开。等到明天早上，我回头眺望家乡的方向，应该能看见山岭上的梅花。`, interpretation: `这首诗是宋之问被贬岭南、路过大庾岭时写下的。大庾岭是南北分界线，过了这里就离家乡越来越远，所以古人传说南飞的大雁到了这儿也要回头。诗人借大雁不肯南飞，反衬自己被迫南行的悲伤。颈联写江潮刚落、瘴气弥漫，是岭南特有的荒凉景象；尾联想象明天回望家乡时能看见岭上梅花，用一抹亮色寄托了浓浓的思乡之情。这首诗把“行行复行行”的离愁写得含蓄动人，是唐人写思乡的好作品。` }] },
  { id: 582, title: "月夜忆舍弟",
    author: "杜甫",
    dynasty: "唐",
    category: "唐",
    summary: "戍鼓断人行，边秋一雁声，露从今夜白，月是故乡明",
    tags: "唐,思乡",
    color: "#f59e0b",
    sections:[    { id: 1, title: "月夜忆舍弟", original: `
戍鼓断人行，
边秋一雁声，
露从今夜白，
月是故乡明
`, translation: `戍楼的鼓声一响，路上就没有行人了。边塞的秋天里，只听见一只大雁的叫声。今夜之后就要进入白露节气了，你看，还是故乡的月亮最明亮啊。`, interpretation: `这首诗写于安史之乱时期，杜甫的弟弟们分散在各地，战乱让亲人难以相聚。诗人通过戍鼓、孤雁、白露、明月这些意象，表达了对弟弟们的深切思念。尤其是“月是故乡明”一句，明明天下的月亮都一样，他却说故乡的最亮，正因为心里装着家乡和亲人，所以看什么都是家乡的好。这种“主观真实”的写法，成了中国思乡诗的经典名句，温暖了一千多年读者的心。` }] },
  { id: 583, title: "和乐天春词",
    author: "刘禹锡",
    dynasty: "唐",
    category: "唐",
    summary: "新妆宜面下朱楼，深锁春光一院愁，行到中庭数花朵，蜻蜓飞上玉搔头",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "和乐天春词", original: `
新妆宜面下朱楼，
深锁春光一院愁，
行到中庭数花朵，
蜻蜓飞上玉搔头
`, translation: `精心打扮着脸蛋走下红楼，庭院深深锁住春光，只剩满心忧愁。走到院子中央去数花朵，一只蜻蜓悄悄飞上她碧玉的发簪。`, interpretation: `这首诗写于唐代，刘禹锡和白居易常以诗唱和。当时妇女妆扮华丽，却因寂寞而愁闷。诗中“新妆”对“春光”，“深锁”对“愁怨”，形成鲜明对比。最妙的是结尾——姑娘本去数花解闷，没想到蜻蜓却飞上她的玉簪，仿佛连小虫都来欣赏她的美，反衬出她无人欣赏的孤单。刘禹锡擅长以乐景写哀情，这首小诗只二十八字，却让人物神态跃然纸上，成为唐诗中写闺怨的佳作。` }] },
  { id: 584, title: "田上",
    author: "崔道融",
    dynasty: "唐",
    category: "唐",
    summary: "雨足高田白，披蓑半夜耕，人牛力俱尽，东方殊未明",
    tags: "唐,民生",
    color: "#f59e0b",
    sections:[    { id: 1, title: "田上", original: `
雨足高田白，
披蓑半夜耕，
人牛力俱尽，
东方殊未明
`, translation: `雨水充足，高处的田地都积满了白白的水。农夫披着蓑衣，半夜就起来耕田。人和牛都已经累得精疲力尽，可是东边的天空还没有亮呢。`, interpretation: `这首小诗写于晚唐，那时农民生活十分辛苦，租税繁重，常常天不亮就下地干活。诗中最打动人的就是“半夜耕”三个字——别人还在睡梦中，农夫已经冒雨劳作了。一句“东方殊未明”更让人心疼：天都没亮，人和牛就已经累得没力气了！全诗没有一句抱怨，却让我们深深感受到农人的辛劳。这种把辛苦藏在画面里的写法，正是唐诗的厉害之处，也让我们明白：碗里每一粒饭，都来之不易。` }] },
  { id: 585, title: "溪居即事",
    author: "崔道融",
    dynasty: "唐",
    category: "唐",
    summary: "篱外谁家不系船，春风吹入钓鱼湾，小童疑是有村客，急向柴门去却关",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "溪居即事", original: `
篱外谁家不系船，
春风吹入钓鱼湾，
小童疑是有村客，
急向柴门去却关
`, translation: `篱笆外面谁家的船没拴好？春风吹着小船，悠悠飘进了钓鱼的河湾。小孩儿以为是有客人来到村里，慌忙跑去打开柴门迎接。`, interpretation: `这首诗写于晚唐，诗人崔道融隐居乡村，描绘了一幅春日小村的趣景。核心意象是'不系船'与'小童'，一个是从容，一个是小孩子的小题大做。诗的妙处在于用孩子的误会反衬出乡村的宁静友好——风吹船来，本无大事，可小童却当真跑去开门，童趣盎然。全诗语言轻快活泼，没有一个'喜'字却处处透出欢喜，是唐诗中难得的田园小趣，后人常用来形容乡村生活的纯朴与天真。` }] },
  { id: 586, title: "太阳礼赞",
    author: "郭沫若",
    dynasty: "近现代",
    category: "近现代",
    summary: "太阳哟我背立在大海边头紧觑着你太阳哟你不把我照得个透明我不回去",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "太阳礼赞", original: `
（版权保护作品，
此处仅展示片段供教学参考）太阳哟我背立在大海边头紧觑着你
`, translation: `太阳啊！我背对着它站在大海的边上，眯着眼睛紧紧地望着你。`, interpretation: `这首诗写于1919年，郭沫若当时留学日本，面对祖国积贫积弱的局面，心中充满苦闷与渴望。当他站在日本海边，看到红日喷薄而出的壮丽景象，便借赞美太阳来表达对光明、自由的强烈向往。诗人背对大海、面朝太阳的姿态很特别，显示出他急切想要拥抱光明的决心。"紧觑"一词特别传神，写出了他目不转睛、渴望光明的神态。这首诗是郭沫若《女神》诗集中的名篇，气势磅礴、想象奔放，开创了中国新诗的新风潮，也影响了后来许多诗人。` }] },
  { id: 587, title: "月之故乡",
    author: "彭邦桢",
    dynasty: "近现代",
    category: "近现代",
    summary: "天上一个，月亮水里，一个月亮，天上的月，亮在水里，水里的月，亮在天上，低头看水，里抬头看，天上看月，亮思故乡",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "月之故乡", original: `
（版权保护作品，
此处仅展示片段供教学参考）天上一个，
月亮水里，
一个月亮，
天上...
`, translation: `天上挂着一个月亮，水里也映着一个月亮。天上的月亮清清亮亮，水里的月亮晃晃悠悠。天底下的月亮只有一个，可抬头看天上、低头看水中，到处都能看见它呀！`, interpretation: `这首小诗写于1970年代，当时许多中国人因种种原因与故乡和亲人分离，看不到同一片天空。诗人借月亮寄托思念：不管身在何方，抬头望见的都是同一个月亮，月光就像一条无形的线，把所有人的心连在一起。诗歌最大的特色是语言像儿歌一样轻快，却藏着深深的乡愁，短小却动人。后来“天上一个月亮，水里一个月亮”成了许多人思念家乡时最爱念的句子，也常被选入华文教材，让一代代孩子学会用简单的文字表达最真的感情。` }] },
  { id: 588, title: "热爱生命",
    author: "汪国真",
    dynasty: "近现代",
    category: "近现代",
    summary: "我不去想是，否能够成功，既然选择了，远方便只顾，风雨兼程我，不去想未来，是平坦还是，泥泞只要热，爱生命一切，都在意料中",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "热爱生命", original: `
（版权保护作品，
此处仅展示片段供教学参考）我不去想是否能够成功既然选择了远方便只顾...
`, translation: `我不再去想能不能取得成功，既然已经选择了远方这条路，我就只管一路上勇往直前。我不去想能否赢得爱情，既然心中已经认定了那份爱，就只管让它在心中熊熊燃烧。我不去想身后会不会袭来寒风冷雨，既然目标是地平线，留给世界的只能是背影。既然前路是满地荆棘和坎坷，命运又会怎样，那就留它去说吧，我依然会一路向前。`, interpretation: `汪国真叔叔的《热爱生命》写于二十世纪九十年代，那时候很多人面对快节奏的生活既充满期待又有些迷茫。这首诗虽然不长，却充满了力量感！它的核心意象是“远方”“地平线”“风雨”“荆棘”，用这些形象告诉我们：人生路上困难重重，但只要认准目标、坚定向前，就一定能走出自己的精彩。整首诗最妙的地方在于它像口号一样铿锵有力，又像对话一样亲切，仿佛汪叔叔拍着你的肩膀说：“别怕，向前走！”这首诗影响了整整一代人，其中的“既然选择了远方，便只顾风雨兼程”成了无数人激励自己的座右铭，每当遇到挫折，大家都会想起它。` }] },
  { id: 589, title: "跨越自己",
    author: "汪国真",
    dynasty: "近现代",
    category: "近现代",
    summary: "我们可以欺，骗别人却无，法欺骗自己，当我们走向，枝繁叶茂的，五月青春就，不再是一个，谜向上的路，总是坎坷又，崎岖要保持，最初的浪漫，真是不容易",
    tags: "近现代,经典",
    color: "#64748b",
    sections:[    { id: 1, title: "跨越自己", original: `
（版权保护作品，
此处仅展示片段供教学参考）我们可以欺，
骗别人却无，
法欺骗自己\...
`, translation: `我们能够骗过别人的眼睛，却没有办法骗过自己的心。`, interpretation: `汪国真是20世纪末到21世纪初深受青少年喜爱的诗人，他的诗语言朴实却充满力量，就像一位温暖的大哥哥在和你聊天。这首《跨越自己》写于改革开放后人们追求理想、突破自我的时代背景下，核心意象是"自我"，告诉我们每个人最大的对手其实是自己——能不能勇敢一点、能不能再坚持一下，都取决于自己内心。诗中最动人的就是"欺骗别人却无法欺骗自己"这句，后来广为流传，提醒小朋友们：做人要诚实，更要对自己真诚。` }] },
  { id: 590, title: "渡桑干",
    author: "贾岛",
    dynasty: "唐",
    category: "唐",
    summary: "客舍并州已十霜，归心日夜忆咸阳，无端更渡桑干水，却望并州是故乡",
    tags: "唐,思乡",
    color: "#f59e0b",
    sections:[    { id: 1, title: "渡桑干", original: `
客舍并州已十霜，
归心日夜忆咸阳，
无端更渡桑干水，
却望并州是故乡
`, translation: `我住在并州这个客店已经整整十年了，归乡的心啊，日日夜夜都在想念咸阳。没想到现在又要渡过桑干河，回头望去，竟然觉得并州成了我的故乡。`, interpretation: `这首诗写于贾岛中年时期，他常年漂泊在外，十年客居并州，却因生活所迫不得不继续北渡桑干河。诗中最动人的是最后一句：明明家乡在咸阳，可回头望去，竟把住了十年的并州当成了故乡——这种"久居成故乡"的心酸，道尽了游子漂泊的无奈。诗人用朴素的语言写出深沉情感，没有华丽辞藻，却字字扎心。这两句"无端更渡"与"却望并州"的对仗，把思乡却不得不离乡的矛盾写得格外动人，成为千古传诵的游子心声。` }] },
  { id: 591, title: "题僧房",
    author: "王建",
    dynasty: "唐",
    category: "唐",
    summary: "名利关心不自由，暗香浮动月明楼，撩人春思花前事，一段风流一段愁",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "题僧房", original: `
名利关心不自由，
暗香浮动月明楼，
撩人春思花前事，
一段风流一段愁
`, translation: `人整天惦记着名利，心里就得不到自由。月光照着小楼，隐隐飘来阵阵花香。春天花前的那些往事，总是撩动着人的思绪。每一段风流的韵事，也都伴着一段忧愁。`, interpretation: `这首诗写于唐朝，那时许多读书人一边想出家清净，一边又放不下功名富贵，心里特别矛盾。王建借住在僧人的房子里，看到月下花香，触景生情，写下了这首小诗。'暗香浮动月明楼'是全诗最有名的一句，月光、花香、小楼，三样东西轻轻叠在一起，画面特别美。诗的妙处在于把'想清静'和'放不下'放在一起读——越想躲开世俗，春天的花和过去的回忆就越来撩拨你，真是又浪漫又有点小烦恼。这首诗让后来的很多人明白：真正的自在，不是住在寺院里，而是心里别老装着事儿。` }] },
  { id: 592, title: "清明日园林寄友人",
    author: "贾岛",
    dynasty: "唐",
    category: "唐",
    summary: "今日清明节，园林胜事偏，晴风吹柳絮，新火起厨烟，杜草开三径，文章忆二贤，几时能命驾，对酒落花前",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "清明日园林寄友人", original: `
今日清明节，
园林胜事偏，
晴风吹柳絮，
新火起厨烟，
杜草开三径，
文章忆二贤，
几时能命驾，
对酒落花前
`, translation: `今天是清明节，园林里美好的事情偏偏特别多。晴朗的春风轻轻吹着，柳絮到处飘飞。厨房里新生的火苗升起了做饭的炊烟。杜若香草铺开了三条小路，我想起古代两位才华出众的贤人。什么时候能坐上马车出发，和朋友一起在落花前举杯畅饮呢？`, interpretation: `这首诗写于清明节，是贾岛约朋友出来玩的小邀请。清明时节天气正好，柳絮飞舞，厨房也升起了新火（古人在清明有换新火的习俗），处处生机勃勃。诗中最有趣的是"杜草开三径"——典故出自汉代蒋诩隐居的故事，门前开了三条小路只等贤友来，表达了诗人对朋友的想念。整首诗语言清新，情景交融，没有华丽辞藻却十分动人。后人常用"落花前"来形容春日雅聚的意境，读来让人心生向往。` }] },
  { id: 593, title: "春草",
    author: "唐彦谦",
    dynasty: "唐",
    category: "唐",
    summary: "天北天南绕路边，托根无处不延绵，萋萋总是无情物，吹绿东风又一年",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "春草", original: `
天北天南绕路边，
托根无处不延绵，
萋萋总是无情物，
吹绿东风又一年
`, translation: `天南地北的路边到处都有它，
没有一处土地它不能扎根蔓延。
茂盛的春草啊看似无情无义，
却年年被东风吹绿，一年又一年。`, interpretation: `这首诗是唐代诗人唐彦谦写的，描写的对象是我们最熟悉不过的春草。在古时候，诗人写春草常常寄托离别愁绪，但唐彦谦笔下的春草却别有一番趣味——它遍布天南地北，路边处处皆是，生命力顽强得无处不在。诗人用“无情”二字来调侃春草，说它好像不懂人间情感，可恰恰是这“无情”的小草，年年准时被东风唤醒，给大地铺上绿装，这种不讲道理的蓬勃生机，反而最让人感动。整首诗语言朴素，读起来像在跟春草聊天，十分亲切，也让我们明白：身边最不起眼的小草，其实藏着最顽强的生命力量。` }] },
  { id: 594, title: "春山夜月",
    author: "于良史",
    dynasty: "唐",
    category: "唐",
    summary: "春山多胜事，赏玩夜忘归，掬水月在手，弄花香满衣，兴来无远近，欲去惜芳菲，南望鸣钟处，楼台深翠微",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "春山夜月", original: `
春山多胜事，
赏玩夜忘归，
掬水月在手，
弄花香满衣，
兴来无远近，
欲去惜芳菲，
南望鸣钟处，
楼台深翠微
`, translation: `春天的山里好玩的事儿真多呀，赏景游玩到了夜里都忘了回家。捧起一把清泉，月亮的光影就落在我手心里。拨弄一下花枝，花香就沾满了我的衣裳。兴致来了，不在乎路有多远，想走的时候却又舍不得这满山的鲜花。向南边远远望去，听到钟声响起的地方，楼台深深藏在那青翠的山色里。`, interpretation: `这首诗写于唐代，那时候诗人们最喜欢结伴春游赏景啦！于良史抓住了春天夜晚山中最迷人的几个画面：山泉、月光、花香、钟声、楼台，构成了一幅清新又幽静的春山夜景图。诗中最妙的就是“掬水月在手”和“弄花香满衣”这两句，双手捧水月影就在掌中跳动，随手拈花香气就染上衣襟，山中美景好像伸手就能抓到，多有趣呀！这种把大自然变成可以“捧”在手里、“穿”在身上的写法，让整首诗充满了童心般的快乐。后来这两句成了千古名句，许多画家和诗人都爱借用这种意境呢。` }] },
  { id: 595, title: "宿石邑山中",
    author: "韩翃",
    dynasty: "唐",
    category: "唐",
    summary: "浮云不共此山齐，山霭苍苍望转迷，晓月暂飞高树里，秋河隔在数峰西",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "宿石邑山中", original: `
浮云不共此山齐，
山霭苍苍望转迷，
晓月暂飞高树里，
秋河隔在数峰西
`, translation: `天上飘浮的云朵都没有这座山高，雾气笼罩着山峦，望去一片苍茫，让人分不清方向。清晨的月亮好像在高高的树丛间穿梭，银河被几座山峰隔开，远远地挂在西边的天空。`, interpretation: `这首诗写于唐代，诗人韩翃夜宿河北石邑山中，描绘了一幅清冷幽深的山间夜景。诗中“云”“山霭”“晓月”“秋河”几个意象层层铺开，先写山高云低，再写晨雾迷离，最后月亮、银河点缀其间，勾勒出山中秋夜的静谧与辽阔。诗人善于用“暂飞”“隔在”等动词，让静止的月和河仿佛有了动态，富有画面感。这首七绝虽不如韩翃《寒食》有名，但语言凝练、意境清远，是唐人写景诗中的佳作。` }] },
  { id: 596, title: "雨过山村",
    author: "王建",
    dynasty: "唐",
    category: "唐",
    summary: "雨里鸡鸣一两家，竹溪村路板桥斜，妇姑相唤浴蚕去，闲着中庭栀子花",
    tags: "唐,田园",
    color: "#f59e0b",
    sections:[    { id: 1, title: "雨过山村", original: `
雨里鸡鸣一两家，
竹溪村路板桥斜，
妇姑相唤浴蚕去，
闲着中庭栀子花
`, translation: `下雨天里，传来一两户人家公鸡的啼叫声。竹林掩映的小溪，村路上的木板桥歪歪斜斜。嫂嫂和小姑互相招呼着，一起去洗蚕种。庭院里，栀子花静静地开着，没人去理会它。`, interpretation: `这首诗是王建在唐代写的一首田园小诗，描绘了山村雨后的清新景象。当时诗人路过一座小村，被眼前宁静优美的景色打动，便写了下来。诗里有几个很美的画面：雨中鸡鸣、斜斜的板桥、姑嫂相唤去洗蚕种，每一样都带着浓浓的乡村生活气息。最妙的是最后一句——栀子花开了满院子，却没人有空欣赏，这反而更显出农家的勤劳和忙碌。这首诗像一幅淡淡的水墨画，用白描的手法写出了山村的宁静与清新，读起来让人心情也跟着安静下来。` }] },
  { id: 597, title: "写情",
    author: "李益",
    dynasty: "唐",
    category: "唐",
    summary: "水纹珍簟思悠悠，千里佳期一夕休，从此无心爱良夜，任他明月下西楼",
    tags: "唐,情感",
    color: "#f59e0b",
    sections:[    { id: 1, title: "写情", original: `
水纹珍簟思悠悠，
千里佳期一夕休，
从此无心爱良夜，
任他明月下西楼
`, translation: `躺在精美的竹席上，望着水波一样的花纹，思念绵绵不断。约定好的相会相隔千里，一夜之间全都落空。从此以后，再也没有心思去欣赏美好的夜晚，任凭那明亮的月光悄悄落到西边的楼下。`, interpretation: `这首诗写于唐代，诗人李益与恋人相约千里之外会面，结果希望落空，心中满是失落与惆怅。诗中最妙的是“从此无心爱良夜”，月光、良夜本该美好，可因为心上人不在身边，连看月亮的兴致都没了，这种“物是人非”的心情特别让人感同身受。后两句已成为千古名句，常被用来形容心碎后的冷淡——连世界再美，也不想多看一眼了。短短二十个字，把失望和孤独写得这么深，李益真是个讲故事的高手！` }] },
  { id: 598, title: "登崖州城作",
    author: "李德裕",
    dynasty: "唐",
    category: "唐",
    summary: "独上高楼望帝京，鸟飞犹是半年程，青山似欲留人住，百匝千遭绕郡城",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "登崖州城作", original: `
独上高楼望帝京，
鸟飞犹是半年程，
青山似欲留人住，
百匝千遭绕郡城
`, translation: `我独自一人登上高楼，远远地望着长安京城。可是鸟儿飞回去，竟然还要走上半年的路程。这里重重的青山好像有意把我挽留，一圈又一圈地把崖州城紧紧环绕。`, interpretation: `这首诗写于唐朝，李德裕是位很有才能的大臣，却遭到坏人陷害，被远远流放到海南崖州。那时候海南还是偏远荒凉之地，离京城长安山高水远。诗里说鸟飞回去都要半年，真是又孤独又心酸。但他不说自己想哭，只写青山环绕，好像要留住他，这种"以景写情"的方法特别妙。"百匝千遭"四个字让人感觉青山像在替他难过，把思乡之情写得又含蓄又深沉，是唐诗里写愁的好句子。` }] },
  { id: 599, title: "汉江临眺",
    author: "王维",
    dynasty: "唐",
    category: "唐",
    summary: "江流天地外，山色有无中，郡邑浮前浦，波澜动远空，襄阳好风日，留醉与山翁",
    tags: "唐,写景",
    color: "#f59e0b",
    sections:[    { id: 1, title: "汉江临眺", original: `
楚塞三湘接，
荆门九派通，
江流天地外，
山色有无中，
郡邑浮前浦，
波澜动远空，
襄阳好风日，
留醉与山翁
`, translation: `楚国边界和湖南三水相连，荆门一带直通九条长江支流。江水滚滚流向天地尽头，远山在云雾中若隐若现。城邑好像浮在江边的水面上，波涛汹涌仿佛摇动了远方的天空。襄阳的风光如此美好，我愿留下来和山翁一起畅饮沉醉。`, interpretation: `这首诗是王维在唐代安史之乱前游历襄阳时写的，描绘了汉江的壮阔景色。诗人站在汉江边远眺，先用'三湘'、'九派'写出水域辽阔，再用'江流天地外'把视线引到天地尽头，'山色有无中'让远山在云雾里时隐时现，像一幅水墨画。'郡邑浮前浦'特别有趣——城邑仿佛飘在水上，'动远空'写波涛似乎能摇动天空，读起来让人有身临其境的感觉。这首诗是王维山水诗的代表作，把汉江的雄浑与朦胧结合得恰到好处，'江流天地外，山色有无中'更是千古传诵的名句。` }] },
  { id: 600, title: "红牡丹",
    author: "王维",
    dynasty: "唐",
    category: "唐",
    summary: "绿艳闲且静，红衣浅复深，花心愁欲断，春色岂知心",
    tags: "唐,咏物",
    color: "#f59e0b",
    sections:[    { id: 1, title: "红牡丹", original: `
绿艳闲且静，
红衣浅复深，
花心愁欲断，
春色岂知心
`, translation: `绿色的叶子悠闲又安静，红色的花瓣颜色深浅不同。花心里好像有浓浓的愁苦，仿佛快要断了。春天美丽的景色，怎么能懂得花儿的心呢？`, interpretation: `这是王维写的一首小诗，题目叫《红牡丹》，可他偏偏不先写红，反而先说“绿艳”——那大片悠闲静默的绿叶。绿色衬底，红色才更耀眼。第二句说花瓣颜色有深有浅，就像人有时高兴有时难过。第三、四句最有意思：诗人居然觉得牡丹花心里藏着愁绪，愁得快要断了！其实呀，这哪是花儿的愁，分明是诗人自己看着花儿、心里有感触，才把感情“借”给牡丹啦。春天再热闹，也未必真懂一朵花的心事。这首诗短短二十字，却让牡丹有了人的心情，非常巧妙，后来很多诗人都爱用这种“把花当人写”的办法呢。` }] },
  { id: 601, title: "阙题",
    author: "刘昚虚",
    dynasty: "唐",
    category: "唐",
    summary: "道由白云尽，春与青溪长，时有落花至，远随流水香，闲门向山路，深柳读书堂，幽映每白日，清辉照衣裳",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "阙题", original: `
道由白云尽，
春与青溪长，
时有落花至，
远随流水香，
闲门向山路，
深柳读书堂，
幽映每白日，
清辉照衣裳
`, translation: `小路随着白云的尽头而消失，春天好像和青青的溪水一样长。时有落花飘到眼前，又远远地随着流水送来阵阵清香。闲静的门对着山路，茂密的柳林深处是读书的厅堂。幽静中日光常常映照，清亮的光辉洒在衣裳上。`, interpretation: `这首诗写于唐代，当时读书人常在山野中筑堂读书，过着清幽自在的生活。诗人用“白云”“青溪”“落花”“流水”“深柳”等意象，营造出一个远离尘世、幽静美好的读书天地。整首诗对仗工整，画面感很强，像是一幅山水画慢慢展开，读起来让人心里也跟着安静下来。其中“时有落花至，远随流水香”一句尤其有名，淡淡几笔就把春天的气息写活了，成了千古传诵的名句，也常被后人用来形容那种不刻意却美好的相遇。` }] },
  { id: 602, title: "柳",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "曾逐东风拂舞筵，乐游春苑断肠后，已带斜阳又带秋，如何肯到清秋日",
    tags: "唐,咏物",
    color: "#f59e0b",
    sections:[    { id: 1, title: "柳", original: `
曾逐东风拂舞筵，
乐游春苑断肠后，
已带斜阳又带秋，
如何肯到清秋日
`, translation: `曾经追着春风，轻轻拂过热闹的歌舞宴席。如今在乐游原的春游赏花之后，却让人伤心断肠。它身上已经染上了夕阳的余晖，又染上了秋天的苍凉。怎么会愿意等到那清冷萧瑟的深秋时节呢？`, interpretation: `这首诗写于晚唐，那时国势衰微，诗人常借物抒怀。诗中的柳树曾是春日里风光无限的角色，在乐游原上被游人赞赏。可现在它已染上暮气和秋意，诗人借柳树的遭遇，悄悄说出自己才华被冷落的郁闷心情。这首诗特别妙在不说自己的苦，而是让柳树替自己叹气，读起来又温柔又心酸。后来人们常用"乐游春苑断肠"来形容美好事物消逝后的失落感。` }] },
  { id: 603, title: "春尽",
    author: "韩偓",
    dynasty: "唐",
    category: "唐",
    summary: "惜春连日醉昏昏，醒后衣裳见酒痕，细水浮花归别涧，断云含雨入孤村",
    tags: "唐,感怀",
    color: "#f59e0b",
    sections:[    { id: 1, title: "春尽", original: `
惜春连日醉昏昏，
醒后衣裳见酒痕，
细水浮花归别涧，
断云含雨入孤村
`, translation: `我太舍不得春天走了，一连好几天喝得醉醺醺的，昏昏沉沉。醒来以后，发现衣裳上到处是喝酒留下的痕迹。细细的溪水载着落花，漂向了另一条山涧。断裂的云带着雨，飘进了孤独的小村庄。`, interpretation: `这首诗写于唐朝快要结束的时候，作者韩偓经历过很多动荡，心里很不是滋味。春天本来是让人开心的，可他却借酒消愁，连着好几天喝得大醉。你看他写得多妙：不说自己伤心，只说衣裳上都是酒印子；不说自己孤单，偏说断云带着雨飘进孤村。落花、流水、断云、孤村，每一个画面都带着淡淡的忧伤。这首诗最厉害的地方就是'以景写情'——把心里话全藏进了风景里，不直接说出来，反而更让人动心。后来很多诗人写惜春、伤感的诗，都会学他这种含蓄又深沉的手法呢。` }] },
  { id: 605, title: "宿骆氏亭寄怀崔雍崔衮",
    author: "李商隐",
    dynasty: "唐",
    category: "唐",
    summary: "秋阴不散霜飞晚，留得枯荷听雨声，竹坞无尘水槛清，相思迢递隔重城",
    tags: "唐,经典",
    color: "#f59e0b",
    sections:[    { id: 1, title: "宿骆氏亭寄怀崔雍崔衮", original: `
竹坞无尘水槛清，
相思迢递隔重城，
秋阴不散霜飞晚，
留得枯荷听雨声
`, translation: `竹林环绕的船坞没有一丝灰尘，水边的栏杆格外清净。我对你们的思念啊，穿过一座又一座的城。秋天的阴云久久不散，霜也来得格外晚。我特意留着那些枯萎的荷叶，好让它们在夜里沙沙地听着雨声。`, interpretation: `这是李商隐在一个秋夜，住在亲戚骆家亭子里写给两个小朋友崔雍、崔衮的。当时他年纪也不大，离家在朋友家借住，心里很孤独。这首诗最厉害的就是最后一句——他不去睡觉，偏要专门留着枯荷叶来听雨声。这个“听雨”啊，表面上写的是雨打在枯叶上的声音，其实是他把对朋友的思念藏进了雨声里。后来“留得枯荷听雨声”成了千古名句，连《红楼梦》里林黛玉都最喜欢这句话呢！` }] },
  { id: 606, title: "送李少府贬峡中王少府贬长沙",
    author: "高适",
    dynasty: "唐",
    category: "唐",
    summary: "巫峡啼猿数行泪，衡阳归雁几封书，青枫江上秋帆远，白帝城边古木疏",
    tags: "唐,送别",
    color: "#f59e0b",
    sections:[    { id: 1, title: "送李少府贬峡中王少府贬长沙", original: `
嗟君此别意如何，
驻马衔杯问谪路，
巫峡啼猿数行泪，
衡阳归雁几封书，
青枫江上秋帆远，
白帝城边古木疏
`, translation: `唉，你们这次分别，心情怎么样呢？我停下马来，举着酒杯，问你们被贬去的地方。巫峡的猿猴悲哀啼叫，听得人泪流成行。衡阳有回飞的大雁，能捎去几封家书。青枫江上秋天的船帆远远离去，白帝城边古老的树木叶子已稀疏。`, interpretation: `这首诗写于唐代，是高适送两位被贬谪的朋友时所作。当时朝廷官员常因得罪权贵被贬到偏远地方，所以这首诗充满了对友人的关切与同情。诗中用了巫峡猿啼、衡阳雁信、青枫江、白帝城等意象，描绘出两座贬所的遥远与凄凉，猿声让人落泪，雁儿寄托家书，画面既伤感又开阔。高适以诗赠别，把牵挂藏在景物里，成为唐代送别诗中的名篇。` }] },
  { id: 607, title: "送人东游",
    author: "温庭筠",
    dynasty: "唐",
    category: "唐",
    summary: "荒戍落黄叶，浩然离故关，高风汉阳渡，初日郢门山，江上几人在，天涯孤棹还，何当重相见，樽酒慰离颜",
    tags: "唐,送别",
    color: "#f59e0b",
    sections:[    { id: 1, title: "送人东游", original: `
荒戍落黄叶，
浩然离故关，
高风汉阳渡，
初日郢门山，
江上几人在，
天涯孤棹还，
何当重相见，
樽酒慰离颜
`, translation: `荒凉的边塞戍楼旁，黄叶纷纷飘落。你胸怀坦荡，告别了古老的关隘。高高的风儿吹过汉阳渡口，初升的太阳映照着郢门山。江上有几个人还在等待着你呢？你像一只孤舟，从遥远的天边归来。什么时候我们才能再次相见啊？到那时，我要斟满酒杯，慰藉你离别后的愁颜。`, interpretation: `这首诗是晚唐诗人温庭筠送别朋友东去时写的。那时候国家不太平，边塞荒凉，许多朋友都远走他乡。诗里用"黄叶""孤棹"这些萧瑟的意象，写出了离别的伤感，但开头"浩然离故关"一句又特别豪迈，朋友的远行不是被迫，而是胸怀大志。诗人想象着江上有人在等你，又盼着重逢时把酒言欢，把思念藏进酒杯里。温庭筠的送别诗写得既深情又开阔，让人在伤感中看到希望，是唐人送别诗里的好作品。` }] },
  { id: 609, title: "秋思赠远",
    author: "张仲素",
    dynasty: "唐",
    category: "唐",
    summary: "博山沉燎绝余香，兰烬金檠怨夜长，为问青青河畔草，几回经雨复经霜",
    tags: "唐,情感",
    color: "#f59e0b",
    sections:[    { id: 1, title: "秋思赠远", original: `
博山沉燎绝余香，
兰烬金檠怨夜长，
为问青青河畔草，
几回经雨复经霜
`, translation: `博山炉里的香已经燃尽，只剩最后一丝余香。灯芯燃成了灰烬，铜灯台在长夜里显得格外凄凉。我忍不住问一问那河边青青的野草，你们经历了几回风雨和寒霜？`, interpretation: `这首诗是唐代张仲素写给远方亲人的秋夜思念之作。秋夜独处，炉香燃尽、灯花落灰，这些日常生活的小细节被诗人用来表达深深的寂寞与等待。结尾以问河畔青草经几番风雨霜寒，既是写秋景萧瑟，更是在问：远方的你，是否也和我一样经历着这般苦熬？这种借自然之问诉说人间离情的手法，含蓄动人。'兰烬金檠怨夜长'一句写尽孤灯难眠的况味，成为后世描写秋夜愁思的经典名句。` }] },
  { id: 611, title: "感遇·江南有丹橘",
    author: "张九龄",
    dynasty: "唐",
    category: "唐",
    summary: "江南有丹橘，经冬犹绿林，岂伊地气暖，自有岁寒心，可以荐嘉客，奈何阻重深，运命惟所遇，循环不可寻",
    tags: "唐,咏物",
    color: "#f59e0b",
    sections:[    { id: 1, title: "感遇·江南有丹橘", original: `
江南有丹橘，
经冬犹绿林，
岂伊地气暖，
自有岁寒心，
可以荐嘉客，
奈何阻重深，
运命惟所遇，
循环不可寻
`, translation: `江南生长着红彤彤的橘子树,经过寒冬依然一片翠绿。难道只是因为那里天气暖和吗?不是的,是因为它本身就有耐寒的品格。本可以把橘子摘下来送给贵客品尝,可惜道路又远又难走,没法送到。人的命运啊,只能看机会,好坏循环的道理实在弄不明白。`, interpretation: `这首诗写于唐朝开元末年,张九龄被奸臣排挤、贬谪到荆州时所作。当时他就像那被山重水阻、运不到长安的丹橘,满腹才华却无人赏识。诗人借橘子不畏严寒、四季常青的特点,象征自己坚守高洁、不向恶势力低头的品格,是中国古典诗歌中著名的'比兴'手法。诗中'自有岁寒心'一句最广为传诵,常被用来赞美那些在逆境中保持本心的人,后来'岁寒三友'(松、竹、梅)的说法也受到了这种精神的影响。` }] },
  { id: 612, title: "次韵梨花",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "梨花淡白柳深青，柳絮飞时花满城，惆怅东栏一株雪，人生看得几清明",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "次韵梨花", original: `
梨花淡白柳深青，
柳絮飞时花满城，
惆怅东栏一株雪，
人生看得几清明
`, translation: `梨花淡淡的白，柳树深深的绿。柳絮随风飞舞的时候，梨花已经开满了整座城。看着东边栏杆旁那一株雪白的梨花，真让人有些惆怅。人的一辈子，能看到几次这样清明的美好时光呢？`, interpretation: `这首诗写于北宋时期，苏轼被贬到外州，心情有些低落。一天他看到院子里的梨花盛开，柳絮纷飞，春光正好，于是有感而发。诗中最妙的是把梨花比作'一株雪'，又用一个'惆怅'说出春光易逝的遗憾。最后一句'人生看得几清明'是千古名句，告诉我们美好的事物总是短暂的，要懂得珍惜眼前的时光。短短四句，有景有情，读来清新又带着一点淡淡的忧伤。` }] },
  { id: 613, title: "纵笔三首",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "白头萧散满霜风，小阁藤床寄病容，报道先生春睡美，道人轻打五更钟",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "纵笔三首", original: `
白头萧散满霜风，
小阁藤床寄病容，
报道先生春睡美，
道人轻打五更钟
`, translation: `白发苍苍的我披着一身风霜，孤零零地躺在这小阁楼的藤床上，一副病恹恹的模样。邻居们互相传告说：苏先生正舒舒服服地春睡呢。哪知道这时候，寺庙里有个道士轻轻敲响了五更的晨钟。`, interpretation: `这首诗写于苏轼被贬到海南儋州时，是他人生最低谷的时期。六十二岁的他白发苍苍、身染疾病，住在简陋的小阁楼里，连像样的床都没有，只能睡藤床。可你读完全诗，会发现一个可爱的老头儿——他睡得又香又甜，邻居们都羡慕地说：苏先生这春觉睡得可真美呀！偏偏这时候，道士敲响了五更钟，把他的好梦给搅了。诗里没有抱怨，没有悲伤，只有一种乐呵呵的豁达。这种“睡个好觉就心满意足”的心态，正是苏轼最了不起的地方——再苦的日子，他也能过出滋味来。后人常说“东坡笑对风雨”，这首小诗就是最好的证明。` }] },
  { id: 614, title: "澄迈驿通潮阁",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "余生欲老海南村，帝遣巫阳招我魂，杳杳天低鹘没处，青山一发是中原",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "澄迈驿通潮阁", original: `
余生欲老海南村，
帝遣巫阳招我魂，
杳杳天低鹘没处，
青山一发是中原
`, translation: `我余生大概就在海南这个村子老去啦，没想到皇帝派人来召我回去，就像当年楚怀王派巫阳去招魂一样。远望天边低垂，鹘鸟都飞得没影了，那细细的一缕青山，就是我的故乡中原啊。`, interpretation: `这首诗写于苏轼被贬海南时期。宋哲宗即位后，苏轼终于接到北归的诏书，他登上通潮阁，北望中原，百感交集。当时他已六十二岁，远在荒远的海南，以为要终老此地，如今忽闻归讯，悲喜交加。诗中用"巫阳招魂"的典故，写自己仿佛死而复生的惊喜；又以鹘鸟飞尽、青山如发丝般细微的夸张，刻画遥望故乡的急切心情。短短四句，情感跌宕起伏，是苏轼晚年最动人的作品之一，"青山一发是中原"尤为千古名句。` }] },
  { id: 615, title: "南乡子·送述古",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "回首乱山横，不见居人，只见城谁似临平，山上塔亭亭迎客，西来送客行，归路晚风清，一枕初寒，梦不成今夜残灯，斜照处荧荧秋雨，晴时泪不晴",
    tags: "宋,送别",
    color: "#06b6d4",
    sections:[    { id: 1, title: "南乡子·送述古", original: `
回首乱山横，
不见居人，
只见城谁似临平，
山上塔亭亭迎客，
西来送客行，
归路晚风清，
一枕初寒，
梦不成今夜残灯，
斜照处荧荧秋雨，
晴时泪不晴
`, translation: `回头望去，乱糟糟的山横在眼前。看不见要送走的人，只看见城楼像临平山上的塔，亭亭玉立迎接着来客。这是从西边送客离去啊。回去的路上晚风清清凉凉。今夜天气刚转寒，枕着枕头也睡不着，残灯的光斜斜地照着，窗外下着细雨亮晶晶的。天晴时泪水却不肯停。`, interpretation: `这首词写于苏轼在杭州做官时，送别好朋友陈述古之后。词里写他送完朋友回头看，山城空空荡荡的，心里很不是滋味。'一枕初寒梦不成'是名句，写夜里冷得睡不着，特别孤单。最妙的是最后'晴时泪'的说法——明明是晴天，眼泪却还在下，这种写法把舍不得朋友的心情写到了骨子里。苏轼的送别词从来不说大道理，就是把心里那股酸酸的感觉一点点说给你听，所以特别打动人。` }] },
  { id: 616, title: "望江南·春未老",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "春未老，风细柳斜斜，试上超然台上看，半壕春水一城花，烟雨暗千家",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "望江南·春未老", original: `
春未老，
风细柳斜斜，
试上超然台上看，
半壕春水一城花，
烟雨暗千家
`, translation: `春天还没有过去，春风细细吹着，柳枝轻轻飘荡。试着登上超然台眺望——半护城河的春水波光粼粼，满城的花儿开得正盛，烟雨蒙蒙中，千家万户都隐在雨雾里。`, interpretation: `这是苏轼在密州（今山东诸城）做太守时写的。熙宁九年，他登上了新修好的超然台，满怀喜悦地写下了这首词。当时他主张变法却处处碰壁，心情有些郁闷，但这首词却明亮开朗，一点也不悲观！词中最妙的是'半壕春水一城花，烟雨暗千家'——只用了十四个字，就像画笔画出了一幅烟雨春景图：水、花、雨、家，多美呀！后来'一城花'和'烟雨暗千家'还经常被人引用来形容春天的城市呢。` }] },
  { id: 617, title: "少年游·润州作代人寄远",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "去年相送余杭门外飞雪似杨花今年春尽杨花似雪犹不见还家",
    tags: "宋,情感",
    color: "#06b6d4",
    sections:[    { id: 1, title: "少年游·润州作代人寄远", original: `
去年相送，
馀杭门外，
飞雪似杨花。
今年春尽，
杨花似雪，
犹不见还家。
对酒卷帘邀明月，
风露透窗纱。
恰似姮娥怜双燕，
分明照、画梁斜。
`, translation: `去年在馀杭门外送你，大雪像杨花一样飘飞。今年春天快要过完了，杨花像雪花一样飞舞，却还是没见你回家。我对着美酒卷起窗帘，邀来明月相伴，冷冷的风露透过窗纱。月光就像嫦娥怜爱那双飞燕一样，斜斜地照在雕花的屋梁上。`, interpretation: `这首词写于苏轼在润州（今镇江）任上，是替别人写给远方亲人的思念之作。北宋时期，士人常常离家做官，亲人分离是常有的事。词中最妙的是"飞雪似杨花"和"杨花似雪"——去年送别是大雪纷飞，今年等待却见杨花飘舞，雪与花、杨花与雪相互重叠，把整整一年的思念都凝在这两个画面里。结尾借嫦娥怜爱燕子、月光照着屋梁来想象家人团圆的模样，温柔又心酸。这首词语言清丽，情感真挚，把等待亲人的焦急和孤单写得非常动人。` }] },
  { id: 618, title: "鹧鸪天·林断山明竹隐墙",
    author: "苏轼",
    dynasty: "宋",
    category: "宋",
    summary: "翻空白鸟时时见，照水红蕖细细香，村舍外古城旁杖，藜徐步转斜阳殷，勤昨夜，三更雨，又得浮生一日凉",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "鹧鸪天·林断山明竹隐墙", original: `
林断山明竹隐墙，
乱蝉衰草小池塘，
翻空白鸟时时见，
照水红蕖细细香，
村舍外，
古城旁，
杖藜徐步转斜阳，
殷勤昨夜三更雨，
又得浮生一日凉
`, translation: `远远的树林尽头，青山清晰地露出来，竹丛掩映着院墙。蝉声杂乱，草丛衰败，池塘的水面显得更小了。抬头望去，白色的鸟儿不时掠过天空。池中的红色荷花映照着水面，散发出细细的清香。我拄着拐杖，慢慢地在村舍外、古城旁散步，夕阳斜斜地照着。想起昨夜三更时分下了一场好雨，又让我在这飘浮不定的人生中，享受到一天清凉的时光。`, interpretation: `这首词写于苏轼被贬黄州时期，词人虽然身处困境，却没有被愁苦压垮。词中描绘了一幅夏日雨后的乡村小景：远山、翠竹、蝉鸣、池塘、白鸟、红荷，还有斜阳下拄杖散步的老人，处处透着恬淡与生机。"翻空白鸟"和"照水红蕖"一上一下、一动一静，对仗精巧，是宋词中写景的经典名句。最妙的是结尾——一场夜雨换来一日清凉，词人在平凡日子里品出了诗意与安慰。这种"苦中作乐"、从细微处发现美好的心境，也正是苏轼最打动人的地方。` }] },
  { id: 619, title: "采桑子·轻舟短棹西湖好",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "轻舟短棹西湖好，绿水逶迤，芳草长堤，隐隐笙歌处处随，无风水面琉璃滑，不觉船移微动涟，漪惊起沙，禽掠岸飞",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "采桑子·轻舟短棹西湖好", original: `
轻舟短棹西湖好，
绿水逶迤，
芳草长堤，
隐隐笙歌处处随，
无风水面琉璃滑，
不觉船移微动涟，
漪惊起沙，
禽掠岸飞
`, translation: `坐着小船，划着短桨，西湖的风景真美呀！碧绿的湖水弯弯曲曲地流淌，长长的堤岸上长满了芬芳的青草。隐隐约约传来悠扬的歌声和乐曲声，一路跟随着船儿。湖面上没有风，平滑得像一块琉璃宝石。不知不觉间，小船已经轻轻移动，荡起了细小的波纹，惊动了沙滩上的水鸟，它们掠过湖岸扑棱棱地飞了起来。`, interpretation: `这首词是欧阳修被贬到颍州后写的，颍州西湖风景秀丽，让他心情舒畅，于是写下十首《采桑子》来赞美它。这首是其中最有名的一首！你看，他就像个会拍照的导游，带着我们坐上小船，一路看绿水、闻花草、听远处飘来的歌声，最后还特意安排了一场“小惊喜”——水鸟被船儿惊飞，画面一下子就活了！这种先静后动、动静结合的写法特别巧妙，整首词读起来像在湖上慢慢游赏，舒服又惬意，让人真想立刻去划船呢！` }] },
  { id: 620, title: "采桑子·清明上巳西湖好",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "清明上巳西湖好，满目繁华，争道谁家，绿柳朱轮走钿车，游人日暮相将去，醒醉喧哗路转堤，斜直到城，头总是花",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "采桑子·清明上巳西湖好", original: `
清明上巳西湖好，
满目繁华，
争道谁家，
绿柳朱轮走钿车，
游人日暮相将去，
醒醉喧哗路转堤，
斜直到城，
头总是花
`, translation: `清明节和上巳节的时候，西湖的风景可真美呀！放眼望去，满是一片繁华热闹的景象。大家都在问：这是谁家的马车过来了？只见柳树绿油油的，红色车轮、镶着金花的车子一辆接一辆地驶过。游人们玩到天快黑了才手拉着手往回走，有的清醒，有的喝醉了，一路热热闹闹、说说笑笑，沿着湖堤慢慢走，转过弯，一直走到城门口，呀！一路上到处都是盛开的鲜花。`, interpretation: `这首词写的是北宋时期清明与上巳节（旧历三月初三，人们会去水边踏青游玩）前后，西湖边热闹欢乐的场面。欧阳修当时在颍州（今天的安徽阜阳）做官，喜爱西湖景色，写下了一组《采桑子》来歌咏它。这首词最特别的地方，是它像一卷慢慢展开的图画，从满湖繁华写起，再到香车宝马、游人如织，最后收束在“满路鲜花”的惊喜中，节奏轻快明亮，让小朋友们读着读着就像跟着一起去西湖踏青啦！` }] },
  { id: 623, title: "钗头凤",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "红酥手黄縢，酒满城春色，宫墙柳东风，恶欢情薄一，怀愁绪几年，离索错错错，春如旧人空，瘦泪痕红浥，鲛绡透桃花，落闲池阁山，盟虽在锦书，难托莫莫莫",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "钗头凤", original: `
红酥手黄縢，
酒满城春色，
宫墙柳东风，
恶欢情薄一，
怀愁绪几年，
离索错错错，
春如旧人空，
瘦泪痕红浥，
鲛绡透桃花，
落闲池阁山，
盟虽在锦书，
难托莫莫莫
`, translation: `你红润柔软的手，捧着一杯黄縢美酒。满城都是春天的景色，皇宫的墙边柳树在东风里摇摆。没想到美好的感情这么短暂，留给我的只有满怀的忧愁。这些年我们分离两地，实在难以诉说。错了，错了，错了！春天还是老样子，人却白白地瘦了。泪水把红色的手帕都浸湿了。桃花纷纷落下，池塘和楼阁冷冷清清。从前的誓言还在心里，可是再也寄不出书信了。不要了，不要了，不要了！`, interpretation: `这首词是陆游晚年回忆年轻时与前妻唐婉的爱情故事而写的。陆游和唐婉原本十分恩爱，却因为陆游母亲不喜欢唐婉，被迫分开。后来两人在绍兴的沈园偶然相遇，唐婉送给陆游一杯酒，陆游心中又悲又悔，就在墙上写下了这首《钗头凤》。词里用'桃花落''池阁闲'这些春天凋零的景象，写出他心里说不完的伤心。虽然陆游和唐婉最后都抱憾而终，但这首词却感动了无数人，'山盟虽在，锦书难托'成了形容爱情错过的千古名句。` }] },
  { id: 624, title: "浪淘沙·丹阳浮玉亭",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "归梦寄吴樯水驿，江程长亭短树塞，鸿轻云暗铁瓮城",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "浪淘沙·丹阳浮玉亭", original: `
归梦寄吴樯水驿，
江程长亭短树塞，
鸿轻云暗铁瓮城
`, translation: `归乡的梦寄托在驶向吴地的船上，沿着水路一程又一程。岸上是长长的古亭和矮矮的树木，远处的山关像是把路都堵住了。大雁飞得又高又轻，天空乌云密布，铁瓮城被笼罩在阴沉沉的云影里。`, interpretation: `这首词写于南宋时期，陆游一生主张抗金，却屡遭排挤，从镇江通判任上被调离，心中满是愁绪。词中“鸿雁”“铁瓮城”等意象，寄托了他对前路的迷茫与对国事的忧虑。云暗、塞远，景中含情，是宋词“借景抒情”的典型手法。这首词虽不如《示儿》那样家喻户晓，却展现了陆游词作中沉郁苍凉的一面，让读者感受到一位爱国诗人心中那份沉甸甸的牵挂。` }] },
  { id: 625, title: "静桥仙·夜闻杜鹃",
    author: "陆游",
    dynasty: "宋",
    category: "宋",
    summary: "茅檐人静蓬窗灯，暗春晚连江风雨，林莺巢燕总无声，但月夜常啼杜宇，催成清泪惊残孤，梦又拣深枝飞去，故山犹自不堪听，况半世飘然羁旅",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "静桥仙·夜闻杜鹃", original: `
茅檐人静蓬窗灯，
暗春晚连江风雨，
林莺巢燕总无声，
但月夜常啼杜宇，
催成清泪惊残孤，
梦又拣深枝飞去，
故山犹自不堪听，
况半世飘然羁旅
`, translation: `茅草屋安静无声，蓬窗下灯火昏黄。暮春的夜晚，连绵的江上风雨不停歇。林中的黄莺和巢里的燕子都悄无声息，只有杜鹃鸟在月夜下不停地啼叫。那声音催出了我满眼泪水，惊醒了我孤单的梦，它又飞向了更深的树枝。我的故乡已经够让人不忍心听了，何况我大半辈子都在外漂泊流浪呢。`, interpretation: `这首词是南宋爱国诗人陆游晚年旅居异乡时所作。当时他一心想收复失地，却屡遭打击，壮志难酬。词中以暮春夜雨、杜鹃悲啼为核心意象，营造出凄凉孤寂的氛围。杜鹃的叫声在中国古诗中常用来寄托家国之痛和思乡之苦，而词人听到它啼哭，不免潸然泪下。艺术上，这首词语言平易却情深意长，先写静景再引出杜宇，层层递进，将听鸟啼的个人感受升华为半生飘零的身世之叹。这一意象对后世影响深远，文天祥、辛弃疾等爱国词人常借杜鹃抒发家国情怀。` }] },
  { id: 626, title: "鹧鸪天·壮岁旌旗拥万夫",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "壮岁旌旗拥万夫，锦襜突骑渡江初，春风不染白髭须，却将万字平戎策，换得东家种树书",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "鹧鸪天·壮岁旌旗拥万夫", original: `
壮岁旌旗拥万夫，
锦襜突骑渡江初，
燕兵夜娖银胡觮，
汉箭朝飞金仆姑，
春风不染白髭须，
却将万字平戎策，
换得东家种树书
`, translation: `年轻时我率领千军万马，旌旗飘扬威风凛凛。锦绣的军衣和精锐的骑兵，当年浩浩荡荡渡江南下。敌军的士兵在夜里整理银色的箭袋，准备战斗。我们的将士清晨便射出金色的利箭，呼啸而去。岁月如春风，却吹不黑我花白的胡须。我洋洋万字的抗敌谋略无人采纳，只好换得东边邻居家的种树书，去过归隐田园的生活。`, interpretation: `这首词写于辛弃疾晚年闲居江西时。年轻时他曾率起义军南渡，是位能征善战的英雄。可南宋朝廷偏安一隅，不思进取，他的满腔报国之志和万字抗敌良策都无人理睬。一个'换'字，写尽了英雄壮志难酬的悲凉。'春风不染白髭须'最妙——人已老，心未老，反衬出词人不肯向命运低头的倔强。辛弃疾的词多写家国情怀，这首短短几句就把将军暮年、壮志未酬的感慨写得动人心魄，成为千古传诵的名篇。` }] },
  { id: 627, title: "清平乐·检校山园书所见",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "西风梨枣，山园儿童偷，把长竿莫遣旁人，惊去老夫静处，闲看",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "清平乐·检校山园书所见", original: `
连云松竹，
万事从今足，
拄杖东家分社肉，
白酒床头初熟，
西风梨枣山园，
儿童偷把长竿，
莫遣旁人惊去，
老夫静处闲看
`, translation: `松树竹林高耸入云，连成一片。
从此以后，什么都不缺，我很满足。
拄着拐杖去东边邻居家，领回社日分的肉。
床头的白酒，刚刚酿熟。
秋风吹过，梨树枣树在山园里摇晃。
小孩子偷偷拿着长竹竿，
别让旁人去吓跑他们。
老夫我，就在清静处，悠闲地看。`, interpretation: `这首词写于辛弃疾晚年闲居江西上饶时，他已是头发花白的老人，报国之志难伸，只好在乡间田园里安度晚年。词中“云松竹”“梨枣山园”勾勒出一片恬静的山野风光，最有趣的是后四句——几个小孩偷拿竹竿打枣，老人不但不赶，反而悄悄躲在旁边看，还叮嘱别把人吓跑，充满了孩子气的慈爱和童心。整首词语言浅白活泼，没有用典，寥寥数笔就把一个安详又有点调皮的乡村老爷爷写得栩栩如生。这种把日常小事写得趣味盎然的写法，正是辛弃疾词中难得的轻松小品。` }] },
  { id: 628, title: "西江月·遣兴",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "醉里且贪欢笑，要愁那得工夫，近来始觉古人书，信著全无是处，昨夜松边醉倒，问松我醉何如，只疑松动要来扶，以手推松曰去",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "西江月·遣兴", original: `
醉里且贪欢笑，
要愁那得工夫，
近来始觉古人书，
信著全无是处，
昨夜松边醉倒，
问松我醉何如，
只疑松动要来扶，
以手推松曰去
`, translation: `喝醉了酒，只顾贪恋欢笑，哪有工夫去发愁？最近我才真正读懂古人的书，相信它反而一点道理都没有。昨晚在松树旁醉倒了，我问松树：我醉成什么样了？只觉得松树摇晃，好像要来扶我。我伸手推开松树说：走开！`, interpretation: `这是辛弃疾罢官闲居江西时写的，表面上喝得醉醺醺、嘻嘻哈哈，其实心里装着报国无门的郁闷。他借酒说反话——说古书全无是处，其实是因为书本上的道理在现实里行不通，满腔才华却无用武之地。最有趣的是他醉倒在松树下，跟松树说话、还推开松树说自己没醉，活脱脱一个倔强又可爱的小老头。这种幽默里藏眼泪的写法，正是辛词的独特魅力。` }] },
  { id: 629, title: "生查子·游雨岩",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "溪边照影行，天在清溪底，天上有行云，人在行云里，高歌谁和余，空谷清音起，非鬼亦非仙，一曲桃花水",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "生查子·游雨岩", original: `
溪边照影行，
天在清溪底，
天上有行云，
人在行云里，
高歌谁和余，
空谷清音起，
非鬼亦非仙，
一曲桃花水
`, translation: `我走在溪水边，低头看见自己的倒影。天好像倒映在清澈的溪水底。天上有飘动的云，我也好像走进了那飘动的云里。我放声高歌，谁能和我一起唱？空旷的山谷里响起了清脆的回声。这声音不是鬼叫，也不是神仙说话，而是桃花流水淙淙的声音。`, interpretation: `这首词是辛弃疾罢官后在江西上饶带湖闲居时写的。雨岩是他常去游玩的地方，那时他心情烦闷，就到大自然里寻找快乐。你看他写得多妙——人站在溪边，天、云、人、影子全都倒映在水里，分不清哪个是真的、哪个是倒的，好像人和天地融成了一体。最后一句最有趣：他对着空山唱歌，回应他的不是人，而是一曲桃花流水！这种“天人合一”的写法，是辛弃疾词里特别厉害的功夫，让我们今天读起来也像走进了一幅山水画，心里特别安静舒服。` }] },
  { id: 630, title: "浣溪沙·常山道中即事",
    author: "辛弃疾",
    dynasty: "宋",
    category: "宋",
    summary: "北陇田高踏水频，西溪禾早已尝新，隔墙沽酒煮纤鳞，忽有微凉何处雨，更无留影霎时云，卖瓜声过竹边村",
    tags: "宋,田园",
    color: "#06b6d4",
    sections:[    { id: 1, title: "浣溪沙·常山道中即事", original: `
北陇田高踏水频，
西溪禾早已尝新，
隔墙沽酒煮纤鳞，
忽有微凉何处雨，
更无留影霎时云，
卖瓜声过竹边村
`, translation: `北边高高的田里，人们忙着踩水车灌溉田地；西边溪水边的稻谷已经早早成熟，可以尝到新米了。隔着一道墙，有人打来酒，正在煮着细细的鱼。突然有一阵微微的凉意，是哪里飘来的雨呢？可是转眼云彩就散了，连影子都留不住。卖瓜人的叫卖声，已经飘过竹林边的村庄了。`, interpretation: `这首词写于辛弃疾闲居江西上饶带湖时期。那时候他一心想收复中原，却只能在乡村田园里生活。南宋的乡村生活是什么样子呢？词人像画画一样，依次展现了六个乡村小景：踩水车、尝新米、买酒煮鱼、阵雨微凉、云散无踪、卖瓜叫唤。短短几句，却有声、有色、有味、有温度。更厉害的是上下两片都用了三个小画面，像电影镜头一样一个接一个，让人看了就忘不掉。这首词让我们看到：原来八百年前乡下生活这么有滋有味呀！` }] },
  { id: 631, title: "一剪梅·舟过吴江",
    author: "蒋捷",
    dynasty: "宋",
    category: "宋",
    summary: "流光容易把人抛，红了樱桃，绿了芭蕉，一片春愁待酒浇，江上舟摇楼上帘，招秋娘渡与泰娘，娇风又飘，飘雨又萧，萧何日归家洗客，袍银字笙调心字，香烧",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "一剪梅·舟过吴江", original: `
一片春愁待酒浇，
江上舟摇，
楼上帘招，
秋娘渡与泰娘娇，
风又飘飘雨又萧，
萧何日归家洗客，
袍银字笙，
调心字香，
烧流光容易把人，
抛红了樱桃绿了，
芭蕉
`, translation: `一片春日的心愁啊，想用酒来把它浇灭。江上小船轻轻摇晃，岸上酒楼的帘子随风招展。秋娘渡和泰娘娇都是有名的地方。风啊不停地吹，雨啊又淅淅沥沥地下着不停。什么时候才能回家，洗去我这身当客的衣裳？银字笙吹出的曲子让人心醉，心字形的香烧出袅袅青烟。美好的时光像流水一样容易过去，把人抛弃——樱桃变红了，芭蕉叶变绿了（转眼间春天已变成了夏天）。`, interpretation: `这首词写于南宋末年，蒋捷坐着船经过江苏吴江，思念家乡。当时国家动荡，许多人背井离乡，所以词里弥漫着浓浓的愁绪。'舟摇''帘招''风飘''雨萧'这些描写，把旅途的漂泊感写得特别生动。最妙的是最后一句'红了樱桃，绿了芭蕉'——樱桃由青变红、芭蕉由黄变绿，时光就在这颜色变化中悄悄溜走啦！这句话后来成了千古名句，用来感叹时光易逝、家国难归，既美又让人心酸。` }] },
  { id: 632, title: "虞美人·听雨",
    author: "蒋捷",
    dynasty: "宋",
    category: "宋",
    summary: "少年听雨歌楼上，红烛昏罗帐，壮年听雨客舟中，江阔云低断雁叫西风，而今听雨僧庐下，鬓已星星也，悲欢离合总无情，一任阶前点滴到天明",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "虞美人·听雨", original: `
少年听雨歌楼上，
红烛昏罗帐，
壮年听雨客舟中，
江阔云低断雁叫西风，
而今听雨僧庐下，
鬓已星星也，
悲欢离合总无情，
一任阶前点滴到天明
`, translation: `年轻的时候，我在歌楼上听雨，烛光昏黄，映着红色的罗帐。壮年的时候，我漂泊在外，在客船上听雨，江面宽阔，乌云低沉，西风里传来孤雁的叫声。如今我老了，在和尚的庙里听雨，两鬓已经长出了点点白发。人生的悲欢离合啊，总是那么无情，我只好听凭台阶前滴滴答答的雨声，一直落到天亮。`, interpretation: `这首词写于南宋灭亡之后，是蒋捷一生的回忆录。少年时的歌楼听雨，浪漫温柔；壮年时在逃难客舟中听雨，满是漂泊的愁苦；老年时在僧庐下听雨，只有孤独和白发。三个画面、三种心境，用‘雨’串起了一生的悲欢。最绝的是最后一句——不抱怨、不挣扎，就让雨一直下到天明吧，这种沉默的哀伤比大哭一场更让人心疼。这首词也成了古人写‘听雨’的巅峰之作，后来很多人写雨，都要拿它来比较。` }] },
  { id: 633, title: "贺新郎·九日",
    author: "刘克庄",
    dynasty: "宋",
    category: "宋",
    summary: "湛湛长空黑更那堪斜风细雨乱愁如织老眼平生空四海赖有高楼百尺看浩荡千崖秋色白发书生神州泪尽凄凉不向牛山滴",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "贺新郎·九日", original: `
湛湛长空黑。
更那堪、斜风细雨，
乱愁如织！
老眼平生空四海，
赖有高楼百尺。
看浩荡、千崖秋色。
白发书生神州泪，
尽凄凉、不向牛山滴。
`, translation: `黑沉沉的天空一片昏暗，怎么还受得了斜风夹着细雨打来，纷乱的愁绪就像织不完的丝。老眼昏花我一生却看遍了四方，多亏有这百尺高楼可以登高望远，眺望着无边无际的山岭秋色。我这白发书生啊，对沦陷的故国伤心落泪，泪水都快要流干了，凄凉得连牛山那份悲秋的泪也显得比不上。`, interpretation: `这首词写于南宋末年，刘克庄眼看国土沦陷、山河破碎，心中又悲又愁。重阳节本是登高望远、欢度佳节的日子，可作者看到的天空却是黑沉沉的，还下着斜风细雨，连老天都像在发愁呢！词中最有意思的是“白发书生神州泪”，说他这个读书人把眼泪都哭干了，旁人掉几滴泪算什么，他流的泪是为整个国家呀！整首词借登高写悲秋，用层层叠加的愁绪表达忧国忧民的心情，读起来让人也跟着鼻酸。这首词也告诉我们：真正的勇敢，不是不流泪，而是哭完了还要继续为国家担忧。` }] },
  { id: 634, title: "玉楼春·别后不知君远近",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "渐行渐远渐无书，水阔鱼沉何处问，夜深风竹敲秋韵，万叶千声皆是恨",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "玉楼春·别后不知君远近", original: `
别后不知君远近，
触目凄凉多少闷，
渐行渐远渐无书，
水阔鱼沉何处问，
夜深风竹敲秋韵，
万叶千声皆是恨，
故欹单枕梦中寻，
梦又不成灯又烬
`, translation: `分别之后我不知道你去了多远，眼前处处都显得凄凉，心里好烦闷。你越走越远，也越来越没有书信寄来，江水又宽又阔，想问个消息，连鱼儿也沉入水底找不到踪影。深夜里风吹竹子，敲打出一片秋天的声音，千万片叶子沙沙作响，仿佛每一声响都是我的怨恨。我斜靠着孤单的枕头，想在梦里找到你，可梦也没做成，灯也已经燃尽成灰。`, interpretation: `这是北宋大文豪欧阳修写给远方友人的一首小词。欧阳修一生写了许多思念亲友的词作，这首便是其中代表。词中最打动人的是那句'渐行渐远渐无书'，连用三个'渐'字，把等待时那种一天比一天焦急、一点一点失望的心情写得特别真切。下片用'风竹''秋声'来衬托内心愁苦，夜里风吹竹叶沙沙作响，好像每一声都在说'想念你'。最后'梦又不成灯又烬'特别有意思：想做个好梦跟你见一面，偏偏睡不着；想熬夜等你消息，偏偏灯又熄了——这种'想什么来不什么'的倒霉劲儿，是不是你也体验过？这首词语言朴素不华丽，却句句说进人心坎里，后来很多写'思念'的诗词都从它这里学手法呢。` }] },
  { id: 635, title: "诉衷情·眉意",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "清晨帘幕卷，轻霜呵手试，梅妆都缘自，有离恨故画，作远山长思，往事惜流芳，易成伤拟歌，先敛欲笑还，颦最断人肠",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "诉衷情·眉意", original: `
清晨帘幕卷，
轻霜呵手试，
梅妆都缘自，
有离恨故画，
作远山长思，
往事惜流芳，
易成伤拟歌，
先敛欲笑还，
颦最断人肠
`, translation: `清晨起来卷起帘子，外面有薄薄的白霜。她呵着气暖手，试着给自己画个梅花妆。这一切都是因为心里有离别的愁恨，所以故意把眉毛画成远山那样细长，想着远方的人。想起过去的美好时光，可惜青春像流水一样容易消逝，太让人伤心了。她想唱歌，可还没开口就先收起了笑容，那想笑又笑不出来的样子，最让人心碎。`, interpretation: `这首词是欧阳修写给一位歌女的小词，写在宋仁宗时期。词里最妙的是'远山眉'这个意象——古人觉得把眉毛画得细长如远山，格外好看。但在这里，女主角画远山眉不是为了美，而是因为思念远方的人，用这个妆容寄托相思。'拟歌先敛，欲笑还颦'是千古名句，写出了歌女强颜欢笑却笑不出的样子，特别打动人心。后来很多诗人写'强笑'、'苦笑'，都受到了这句的影响。整首词短短几句，却把一个女子的思念和心酸写得入木三分，特别适合孩子们体会古诗词中细腻的情感。` }] },
  { id: 636, title: "望江南·江南月",
    author: "王琪",
    dynasty: "宋",
    category: "宋",
    summary: "江南月，清夜满西楼，云叶开时千里雪，水华深处一船秋",
    tags: "宋,写景",
    color: "#06b6d4",
    sections:[    { id: 1, title: "望江南·江南月", original: `
江南月，
清夜满西楼，
云叶开时千里雪，
水华深处一船秋
`, translation: `江南的月光多么清亮，洒满了西边的楼房。
云彩散开的时候，千里大地像铺上了一层雪。
水面上的荷花深处，
有一只小船，载着满满的秋意在漂荡。`, interpretation: `这首词是宋代王琪写的《望江南》，专门描绘江南夜晚的月色。词人借三个画面带我们走进江南的秋夜：清亮的月光爬上西楼，这是抬头望天的远景；云散开，千里大地银白一片，像下了雪一样，这是大地披上月色的壮观；水面荷花深处，一叶小舟载着秋意，这是贴近水面的静美。短短几句，有高有低，有动有静，色彩、声音、气息都齐全了。词人没用一个"美"字，却把江南月夜写得像画一样。"千里雪"和"一船秋"的对仗尤其巧妙，一远一近、一白一青，让画面立刻立体起来。这首词告诉我们：写景不用堆词，对仗和想象才是好帮手。` }] },
  { id: 637, title: "杏花天影",
    author: "姜夔",
    dynasty: "宋",
    category: "宋",
    summary: "绿丝低拂鸳鸯浦想桃叶当时唤渡又将愁眼与春风待去倚兰桡更少驻金陵路莺吟燕舞算潮水知人最苦满汀芳草不成归日暮更移舟向甚处",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "杏花天影", original: `
绿丝低拂鸳鸯浦。
想桃叶、当时唤渡。
又将愁眼与春风，
待去。
倚兰桡、更少驻。
金陵路。
莺吟燕舞。
算潮水、知人最苦。
满汀芳草不成归，
日暮。
更移舟、向甚处。
`, translation: `水边柳丝轻垂，拂过鸳鸯栖息的小渡口。我想起当年桃叶曾在这里呼唤渡船。春风里，我用愁眉望着远方，打算离去。靠着兰花般的船桨，我让船再停留一会儿。前方是通往金陵的路，耳边传来黄莺的啼唱和燕子飞舞的声音。要说这世上谁最懂我的苦楚，恐怕只有那潮水了。岸边长满了芳草，我却回不去。太阳已经落山了。我又该把船划向哪里呢？`, interpretation: `这是南宋词人姜夔路过金陵时写下的词。当时他漂泊四方，心里装着对心上人的思念。词里最动人的意象是那双"愁眼"和懂人的"潮水"——你看，他不说自己想家，偏说潮水最懂他的苦，这就是姜夔的厉害之处，用拟人让江水都变得贴心。整首词就像一首轻轻的船歌，"鸳鸯""桃叶""莺燕"都是温暖热闹的词，可写的人心里却孤零零的，这种热闹里的孤单，特别打动后人。后来很多画家都爱画这首词的意境，连那句"算潮水、知人最苦"都被当成经典的伤心话传了下来。` }] },
  { id: 638, title: "点绛唇·丁未冬过吴松作",
    author: "姜夔",
    dynasty: "宋",
    category: "宋",
    summary: "燕雁无心，太湖西畔，随云去数峰清苦，商略黄昏，雨第四桥边，拟共天随，住今何许，凭阑怀古残柳参，差舞",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "点绛唇·丁未冬过吴松作", original: `
燕雁无心，
太湖西畔，
随云去数峰清苦，
商略黄昏，
雨第四桥边，
拟共天随，
住今何许，
凭阑怀古残柳参，
差舞
`, translation: `北方的鸿雁毫无心思，就在太湖的西边，随着云彩飞过几座清冷孤苦的山峰。细雨蒙蒙，黄昏将近，我站在第四桥边。想要和唐代陆龟蒙一起住在这里，可如今他在哪里呢？我靠着栏杆怀念古人，只有岸边参差不齐的残柳在风中舞动。`, interpretation: `这是南宋词人姜夔在宋孝宗淳熙十四年冬天，途经吴松（今苏州一带）时写下的。当时南宋偏安江南，词人漂泊四方，心中常怀故国之思和身世之感。词中“燕雁”“残柳”是核心意象——燕雁南飞却“无心”，残柳飘零无力，都寄托了词人漂泊无依、孤独清冷的情绪。姜夔的词讲究“清空”意境，这首词化用唐代诗人陆龟蒙（号天随子）的典故，融情于景，含蓄隽永。结尾“残柳参差舞”画面感极强，成为千古名句，让读者仿佛看见一位清瘦的词人独立桥头，听雨怀古，意境悠远绵长。` }] },
  { id: 639, title: "踏莎行·自沔东来",
    author: "姜夔",
    dynasty: "宋",
    category: "宋",
    summary: "淮南皓月，冷千山冥，冥归去无人管燕，燕轻盈莺，莺娇软分，明又向华胥见夜，长争得薄，情知春初，早被相思染别后，书辞别时，针线离魂，暗逐郎行远",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "踏莎行·自沔东来", original: `
燕燕轻盈，
莺莺娇软，
分明又向华胥见，
夜长争得，
薄情知春，
初早被相思染别，
后书辞别，
时针线离，
魂暗逐郎行远淮，
南皓月冷，
千山冥冥，
归去无人管
`, translation: `燕子轻轻飞，姿态多轻盈；黄莺娇声啼，叫得真柔软。分明是在梦里，又和她相见。长夜漫漫睡不着，你怎么还不明白我的痴情？早春的景色刚刚到来，就被我满心的思念染上了离别的愁绪。临别时她匆匆写信，说要分别。针线活儿也撂下了不碰，相思的魂魄悄悄地跟着郎君远行。一路来到淮南，天上的明月清冷地照着，千山万岭一片昏暗。回去吧，没有人来管我。`, interpretation: `这首词是南宋词人姜夔写的。姜夔一辈子没做过大官，靠写词卖字过日子，他笔下的爱情故事常常带着清冷和孤独的感觉。词里用了"燕子""黄莺"两个可爱的小动物来写梦中的恋人，又用"明月""千山"这样又大又冷的景象来衬托旅途的孤单。最有意思的是"初早被相思染别"这一句——春天刚来，树叶刚绿，可姑娘心里已经全被思念染成离别的颜色了，多巧妙！整首词就像一场朦朦胧胧的梦，梦里的人越走越远，醒来只剩空荡荡的月光。这种"梦里寻人，醒后更愁"的写法，后来被好多词人学着用呢。` }] },
  { id: 641, title: "浣溪沙·堤上游人逐画船",
    author: "欧阳修",
    dynasty: "宋",
    category: "宋",
    summary: "堤上游人逐画船，拍堤春水四垂天，绿杨楼外出秋千，白发戴花君莫笑，六幺催拍盏频传，人生何处似尊前",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "浣溪沙·堤上游人逐画船", original: `
堤上游人逐画船，
拍堤春水四垂天，
绿杨楼外出秋千，
白发戴花君莫笑，
六幺催拍盏频传，
人生何处似尊前
`, translation: `湖堤上，游人一个接一个地追着彩船跑。湖水拍打着堤岸，春水浩荡，仿佛和四面低垂的天连成一片。绿杨掩映的高楼外，传来姑娘荡秋千的欢笑声。头发白了也照样把鲜花戴在头上，你别笑话我啊。乐曲《六幺》节奏越来越快，酒杯频频传来。人生哪一段能比得上这喝酒欢乐的时刻呢？`, interpretation: `这是欧阳修晚年任颍州（今安徽阜阳）知州时写的，描绘春日西湖的游赏之乐。当时他经历了宦海浮沉，被贬多次后重回京城又外放，心境渐趋豁达乐观。词中“拍堤春水四垂天”一句尤为绝妙，把湖水与天空相接的壮阔画面写得生动如画；“绿杨楼外出秋千”一个“出”字，让秋千少女从柳荫中跃入眼帘，满满的春意扑面而来。结尾“人生何处似尊前”，看似洒脱，实则藏着几分对人生坎坷的感慨。这首词把热闹的宴游场面写得有声有色，成为宋词中写春游的经典名篇。` }] },
  { id: 643, title: "千秋岁",
    author: "张先",
    dynasty: "宋",
    category: "宋",
    summary: "天不老情难绝心似双丝网中有千千结夜过也东方白未凝睫数声鶗鴂又报芳菲歇惜春更把残红折雨轻风色暴梅子青时节",
    tags: "宋,经典",
    color: "#06b6d4",
    sections:[    { id: 1, title: "千秋岁", original: `
数声鶗鴂。
又报芳菲歇。
惜春更把残红折。
雨轻风色暴，
梅子青时节。
永丰柳，
无人尽日飞花雪。
莫把幺弦拨。
怨极弦能说。
天不老，
情难绝。
心似双丝网，
中有千千结。
夜过也，
东窗未白凝残月。
`, translation: `几声杜鹃在啼叫，又在报告说花儿已经凋谢。舍不得春天离去，便把残留的红花折下收藏。雨丝轻柔，风却劲吹，正是梅子泛青的时节。永丰坊的柳树啊，无人欣赏，整日只有柳絮像雪花一样飘飞。别去拨动那最细的琴弦啊，愁怨到了极点，琴弦也能倾诉。天不会老去，情也难以断绝。我的心像一张用双丝织成的网，里面有无数个解不开的结。夜晚过去了，窗子还没亮，只有一弯残月挂在天边。`, interpretation: `这首词是北宋词人张先的经典伤春之作。北宋时期，词人们在小小的篇幅里藏着深深的心事，特别喜欢用“伤春”来寄托对朋友或情人的思念。这首词最妙的地方，是把春天慢慢消逝的过程写得丝丝入扣：先听杜鹃叫，再看花落，然后是梅子青青、柳絮纷飞，一步步把读者带进“春天已经走了”的感伤里。最有名的句子是“心似双丝网，中有千千结”，把心里说不清、道不明的愁绪比作一张千缠万绕的丝网，里面的结怎么也解不开。这个比喻又新鲜又贴切，后来“千千结”就成了人们形容深情的常用词。整首词情景交融，情感真挚，特别适合在春天快要结束的时候读一读。` }] },
  { id: 644, title: "蝶恋花·出塞",
    author: "纳兰性德",
    dynasty: "清",
    category: "清",
    summary: "今古河山无定据，画角声中，牧马频来去，满目荒凉谁可语，西风吹老丹枫树",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "蝶恋花·出塞", original: `
今古河山无定据，
画角声中，
牧马频来去，
满目荒凉谁可语，
西风吹老丹枫树，
从前幽怨应无数，
铁马金戈，
青冢黄昏路，
一往情深深几许，
深山夕照深秋雨
`, translation: `古往今来，这山河的归属变化不定，根本没有定数。号角声声中，敌人的骑兵不断来去侵扰。眼前一片荒凉破败，我又能和谁诉说？只有西风不停吹着，把那火红的枫树都吹得苍老了。从前积累的幽怨愁苦不知有多少。想当年铁马金戈、战火纷飞，如今只留下青冢矗立在黄昏的路上。我这一片深情究竟有多深呢？就像那深山里的夕阳，又像深秋时节的冷雨，绵绵不绝。`, interpretation: `这首词写于康熙年间，纳兰性德随皇帝出巡塞外时所作。词中描绘了边塞战场的荒凉景象，号角声、牧马、丹枫、青冢等意象，诉说着古往今来战争的残酷与历史的沧桑。其中'一往情深深几许，深山夕照深秋雨'是千古名句，用深山夕阳和深秋冷雨来比喻深沉的情意，意境悠远，感人至深。纳兰的词以情感真挚著称，这首《出塞》更是在边塞题材中融入了个人情怀，让冰冷的战场有了温度，是中国古代边塞词中的经典之作。` }] },
  { id: 645, title: "浣溪沙·残雪凝辉冷画屏",
    author: "纳兰性德",
    dynasty: "清",
    category: "清",
    summary: "残雪凝辉冷画疏，梅吹笛已三更更，无人处月胧明我，是人间惆怅客知，君何事泪纵横断，肠声里忆平生",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "浣溪沙·残雪凝辉冷画屏", original: `
残雪凝辉冷画疏，
梅吹笛已三更更，
无人处月胧明我，
是人间惆怅客知，
君何事泪纵横断，
肠声里忆平生
`, translation: `残留的雪映着冷冷的月光，洒在画屏上。
梅花旁边，有人吹着笛子，已经到了三更天。
没有人的地方，月亮朦胧而明亮。
我知道自己是这世上最忧愁伤感的人。
你为什么事而泪流满面？
在让人断肠的声音里，我回忆起自己的一生。`, interpretation: `纳兰性德是清朝著名词人，出身贵族，却一生多愁善感。这首词写于雪夜：残雪、月光、画屏、梅花、笛声，构成了一幅清冷孤寂的夜景图。词中的“惆怅客”是他的自我写照——明明身在富贵之家，内心却无比孤独。他借笛声的悲凉，抒发了对人生无常的感慨。纳兰的词以“真情”二字著称，不堆砌华丽辞藻，却能直击人心，这首词便是其中的代表。` }] },
  { id: 646, title: "桂殿秋",
    author: "朱彝尊",
    dynasty: "清",
    category: "清",
    summary: "思往事，渡江干，青蛾低映越山看，共眠一舸听秋雨，小簟轻衾各自寒",
    tags: "清,经典",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "桂殿秋", original: `
思往事，
渡江干，
青蛾低映越山看，
共眠一舸听秋雨，
小簟轻衾各自寒
`, translation: `回想从前的事情，我们一起渡过江边。你低垂的眉毛像青山一样秀丽，倒映在越山的风景中。我们同坐在一条小船上，听着淅淅沥沥的秋雨声。如今各自睡在竹席和薄被里，感到一阵阵凉意。`, interpretation: `这是清朝词人朱彝尊年轻时写给小姨子（妻子的妹妹）冯寿常的恋词。词中回忆两人曾同船渡江、听雨相处的美好往事，那时姑娘的眉毛像远山一样青秀美丽。可现在却只能各自独眠，秋雨添寒，心中充满思念与惆怅。短短几句，用"渡江""听雨""小簟轻衾"几个画面，把过去的甜蜜和今日的孤单对比得格外动人。这首词语言清丽、意境幽远，是清代爱情词中的经典名篇，也让"共眠一舸听秋雨"成为流传千古的名句。` }] },
  { id: 647, title: "卖花声·雨花台",
    author: "朱彝尊",
    dynasty: "清",
    category: "清",
    summary: "秋草六朝寒，花雨空坛，更无人处一凭阑，燕子斜阳来又去，如此江山",
    tags: "清,感怀",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "卖花声·雨花台", original: `
秋草六朝寒，
花雨空坛，
更无人处一凭阑，
燕子斜阳来又去，
如此江山
`, translation: `秋天的野草在六朝古都散发着寒意，落花如雨飘洒在空旷的古坛上。没有人陪伴，我独自靠着栏杆远眺。燕子在夕阳下飞来又飞去，这片山河依旧如此，却已人事全非。`, interpretation: `这是清代词人朱彝尊的怀古之作。雨花台在南京，是六朝旧地。词人站在古战场上，看见秋草凄寒、落花纷飞，燕子依旧在斜阳下穿梭，可当年繁华的六朝早已灰飞烟灭。一个"寒"字写出历史冷寂感，"更无人处"道出孤独。最妙的是结尾——江山还是那片江山，却让人忍不住想问：那些英雄豪杰都去了哪里？短短几句，把对历史变迁的感慨写得深沉又优美，是清词中咏史的佳作。` }] },
  { id: 648, title: "水调歌头·题西山秋爽图",
    author: "纳兰性德",
    dynasty: "清",
    category: "清",
    summary: "何日得投簪，松下饭胡麻，绝顶茅庵里，老衲正谈经",
    tags: "清,写景",
    color: "#1d4ed8",
    sections:[    { id: 1, title: "水调歌头·题西山秋爽图", original: `
空山梵呗静，
水月影俱沉，
悠然一境人外，
都不许尘侵，
岁晚忆曾游处，
犹记半竿斜阳，
一抹界疏林，
绝顶茅庵里，
老衲正谈经
`, translation: `空旷的山里传来寺庙的诵经声，安安静静的。水中的月影和天上的月影一起沉了下去。在这人世之外的地方，有一片悠然自得的天地，一点儿灰尘都飘不进来。想起那年深秋曾经游玩过的地方，还记得那斜斜的太阳刚刚落下半根竹竿高，一道亮光隔开了稀疏的树林。山顶的小茅草屋里，老和尚正在讲解佛经呢。`, interpretation: `这首词是清朝著名词人纳兰性德画的题画词，写在一幅叫《西山秋爽图》的画上。词人看着画中山寺清幽的景色，仿佛自己也走进了画里。词中藏着几个特别美的意象：空山、梵呗、水月、疏林、茅庵，全是安静又干净的东西，看一眼心里就静下来了。整首词像一幅小画，读起来也像在画里散步。纳兰性德最厉害的就是用短短几个字，写出又清又远的感觉，这首词正是他拿手风格的代表。` }] },
  { id: 649, title: "上小楼·隐居",
    author: "任昱",
    dynasty: "元",
    category: "元",
    summary: "荆棘满途，蓬莱闲住，诸葛茅庐，陶令松菊，田父酒初，欢来也各，自分去",
    tags: "元,田园",
    color: "#ec4899",
    sections:[    { id: 1, title: "上小楼·隐居", original: `
荆棘满途，
蓬莱闲住，
诸葛茅庐，
陶令松菊，
田父酒初，
欢来也各，
自分去
`, translation: `一路上到处都是荆棘丛生啊，我就在蓬莱仙境一样的地方悠闲地住下。住的是诸葛亮当年住过的茅草屋，种的是陶渊明喜爱的松树和菊花。田里种地的老农送来新酿好的酒，我高兴地和大家一起喝，喝完各自散去，各享各的自在。`, interpretation: `这是元朝散曲家任昱写的一首小令。写这首曲子的时候，元朝读书人的日子不太好过，想做官常常碰壁，所以很多人就选择隐居。这首小曲就是写隐居生活的快乐：住的是草屋，种的是松菊，喝酒的是农夫朋友，多么自在呀！曲子短短几句，连用“蓬莱”“诸葛茅庐”“陶令松菊”这些典故，好像在说：我虽然隐居，可不是普通人哦，过的是神仙、诸葛亮、陶渊明一样的日子！语言俏皮，短短的句子一个接一个，读起来特别有节奏感，像是在快快乐乐地报菜谱呢。` }] },
  { id: 650, title: "清江引·秋思",
    author: "张可久",
    dynasty: "元",
    category: "元",
    summary: "西风信来家万里问我归期未雁啼红叶天人醉黄花夜芭蕉雨声秋梦里",
    tags: "元,感怀",
    color: "#ec4899",
    sections:[    { id: 1, title: "清江引·秋思", original: `
西风信来家万里，
问我归期未？
雁啼红叶天，
人醉黄花夜，
芭蕉雨声秋梦里
`, translation: `西风送来书信问我何时回家？我离家万里，归期还没定下。秋天的雁在红叶满天中啼叫，天空高远，我沉醉在菊花丛中。夜里，雨点打在芭蕉叶上，我在秋天的梦里思念家乡。`, interpretation: `这首小令写于元代，那时许多文人漂泊在外，想回乡却回不去。张可久用"西风"、"雁啼"、"红叶"、"黄花"、"芭蕉雨"这一连串秋天景物，层层堆出浓浓的思乡之情。最妙的是结尾——雨打芭蕉的声响把人送入秋梦，可梦里还是家乡。整首曲子像一幅水墨画，意境清远，被后人称赞是元代散曲中写秋思的佳作，那句"西风信来家万里"尤其动人。` }] },
  { id: 651, title: "醉太平·夺泥燕口",
    author: "无名氏",
    dynasty: "元",
    category: "元",
    summary: "夺泥燕口削铁针头刮金佛面细搜求无中觅有鹌鹑嗉里寻豌豆鹭鸶腿上劈精肉蚊子腹内刳脂油亏老先生下手",
    tags: "元,讽刺",
    color: "#ec4899",
    sections:[    { id: 1, title: "醉太平·夺泥燕口", original: `
夺泥燕口，
削铁针头，
刮金佛面细，
搜求无中觅有。
鹌鹑嗉里寻豌豆，
鹭鸶腿上劈精肉，
蚊子腹内刳脂油。
亏老先生下手
`, translation: `从燕子嘴里夺泥巴，从针头上削铁屑，从佛脸上刮金粉，细细搜求，把没有的说成有。在鹌鹑的喉咙里找豌豆，在鹭鸶的细腿上劈精肉，在蚊子肚子里剖脂油——这些缺德的事，只有老先生您才干得出来！`, interpretation: `这支小令诞生在元代。那时候官员贪婪成风，老百姓苦不堪言，百姓就用民间小曲来骂他们。曲子最妙的地方是夸张：燕子嘴里那么点泥、蚊子肚子里那点油，贪官都不放过，真是贪到了极点！'夺''削''刮''刳'这些动词一个比一个狠，画面感十足。这种'小事里见大贪'的写法，后来成了讽刺文学的经典套路，今天读来还让人拍手叫绝。` }] },
  { id: 652, title: "塞鸿秋·代人作",
    author: "贯云石",
    dynasty: "元",
    category: "元",
    summary: "战西风几点宾鸿，至感起我南朝千，古伤心事展花笺，欲写几句知心事，空教我停霜毫半，晌无才思往常得，兴时一扫无瑕疵，今日个病恹恹刚，写下两个相思字",
    tags: "元,情感",
    color: "#ec4899",
    sections:[    { id: 1, title: "塞鸿秋·代人作", original: `
战西风几点宾鸿，
至感起我南朝千，
古伤心事展花笺，
欲写几句知心事，
空教我停霜毫半，
晌无才思往常得，
兴时一扫无瑕疵，
今日个病恹恹刚，
写下两个相思字
`, translation: `西风吹来，几只大雁飞过，这景象让我突然想起江南那些让人伤心的事。铺开带花纹的信纸，想写几句心里话，可笔却停住了，半晌也写不出一个字。以前兴致好的时候，一气呵成，文章没有半点毛病。今天我病恹恹的，刚写下去，就只有'相思'两个字。`, interpretation: `这首小令是元代散曲家贯云石代人所作的怀乡之作。贯云石本是维吾尔族贵族，自幼读汉文、习汉学，后弃官隐居江南，对故土与新居都有深情。曲中借秋雁南飞的画面，触动游子内心愁绪——西风、宾鸿是典型的思乡意象，花笺、霜毫（白色毛笔）则营造出书斋独处的氛围。这首曲最妙在对比手法：往常才思敏捷、笔下生辉，今日却'停霜毫半晌无才思'，反衬出愁病之深。结尾'写下两个相思字'戛然而止，余味无穷，让人仿佛看到一位伏案凝思、欲说还休的伤心人。这种以乐景衬哀情、以今昔对比写愁的手法，在元散曲中很有代表性，读来亲切动人。` }] },
  { id: 653, title: "红绣鞋·天台瀑布寺",
    author: "张可久",
    dynasty: "元",
    category: "元",
    summary: "绝顶峰攒雪剑悬，崖水挂冰帘倚树，哀猿弄云尖血华，啼杜宇阴洞吼飞，廉比人心山未险",
    tags: "元,写景",
    color: "#ec4899",
    sections:[    { id: 1, title: "红绣鞋·天台瀑布寺", original: `
绝顶峰攒雪剑悬，
崖水挂冰帘倚树，
哀猿弄云尖血华，
啼杜宇阴洞吼飞，
廉比人心山未险
`, translation: `最高的山峰上积雪堆聚，像一把把雪亮的宝剑悬挂在空中。悬崖上的瀑布冻成了冰帘，靠着树木垂挂下来。哀伤的猿猴在云间玩耍，声音像尖尖的血花在飞溅。杜鹃在阴暗的山洞里啼叫，声音大得能把阴间都震吼起来。山虽然险峻，但比起人心来还不算最险。`, interpretation: `这是元代散曲家张可久写的写景小令。他游历天台山瀑布寺，用短短几句就把冬天山顶的奇景写活了：雪山像剑、冰瀑像帘、猿声凄厉、杜鹃悲啼，越写越险，最后却笔锋一转，说人心比山还险！这种"以景衬理"的写法在当时很流行，让人在欣赏美景的同时，也得到一点人生感悟。读起来节奏感很强，像唱歌一样，是元曲里的小精品。` }] },
  { id: 654, title: "观书",
    author: "于谦",
    dynasty: "明",
    category: "明",
    summary: "书卷多情似故人，晨昏忧乐每相亲，眼前直下三千字，胸次全无一点尘，活水源流随处满，东风花柳逐时新，金鞍玉勒寻芳客，未信我庐别有春",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "观书", original: `
书卷多情似故人，
晨昏忧乐每相亲，
眼前直下三千字，
胸次全无一点尘，
活水源流随处满，
东风花柳逐时新，
金鞍玉勒寻芳客，
未信我庐别有春
`, translation: `书本像老朋友一样有情意，无论清晨黄昏、忧愁快乐时都与我相伴。眼睛一目十行地飞快读下去，心中再无半点杂念。书中如活水一般到处涌流，又像春风让花草柳枝时时焕然一新。那些骑着金鞍玉马去寻花问柳的富贵人，不相信我的书屋里也藏着别样的春光。`, interpretation: `这是明代民族英雄于谦写的一首读书诗。诗人把书比作多情的老朋友，生动地写出了读书时那种亲密无间、如沐春风的感觉。诗中运用了'活水'和'东风'两个意象：读书就像活水涌流，源源不断带来新知；又好比东风吹拂，让百花柳树日日更新。结尾两句尤其有趣——那些骑着华贵马匹去踏青赏景的人，哪里知道我这个小小书屋里，自有别样的春天呢？全诗语言明白如话，却把读书的快乐写得淋漓尽致，告诉小朋友：最好的春光，就藏在书本里。` }] },
  { id: 656, title: "蟾宫曲·雪",
    author: "薛昂夫",
    dynasty: "元",
    category: "元",
    summary: "天仙碧玉琼瑶点，点扬花片片鹅毛，访戴归来寻梅懒，去独钓无聊一个，饮羊羔红炉暖阁，一个冻骑驴野店，溪桥你自评跋那，个清高那个粗豪",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "蟾宫曲·雪", original: `
天仙碧玉琼瑶点，
点扬花片片鹅毛，
访戴归来寻梅懒，
去独钓无聊一个，
饮羊羔红炉暖阁，
一个冻骑驴野店，
溪桥你自评跋那，
个清高那个粗豪
`, translation: `雪花像天上的仙女撒下的碧玉和美玉，点点扬花，片片鹅毛，纷纷飘落。有的人像王徽之雪夜访戴一样兴致勃勃，访友归来后却懒得去寻梅了；有的人独自在雪中垂钓，无所事事；有的人围着小火炉，在温暖的阁楼里喝着美酒；有的人却冻得骑着驴子，在荒野的小店里瑟瑟发抖。你自己来评评看：溪边桥头那两种人，谁更高洁清雅，谁更粗犷豪迈？`, interpretation: `这首小令写于明代，作者薛昂夫借雪天的不同场景，刻画了几种人面对大雪时截然不同的生活态度。时代背景下，文人雅士赏雪各有趣味，有的访友、寻梅、饮酒，有的则受冻奔波。'碧玉琼瑶'、'扬花''鹅毛'这些意象生动写出雪花之美与轻盈。艺术上最妙的是对比手法——暖阁饮羊羔与冻骑驴野店，清高与粗豪，一暖一寒、一雅一俗，相映成趣。结尾把'评说'的主动权交给读者，俏皮又耐人寻味，读来让人会心一笑，也让人思索：风雪之中，你想做哪一种人呢？` }] },
  { id: 657, title: "入京",
    author: "于谦",
    dynasty: "明",
    category: "明",
    summary: "绢帕麻菇与线香，本资民用反为殃，清风两袖朝天去，免得闾阎话短长",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "入京", original: `
绢帕麻菇与线香，
本资民用反为殃，
清风两袖朝天去，
免得闾阎话短长
`, translation: `绢帕、麻菇和线香这些东西，本来都是供百姓日常使用的，现在却被官吏搜刮去当作讨好上司的礼品，反而给老百姓带来了灾殃。我两手空空，只带两袖清风进京去，这样就能免得街坊邻里们在背后议论纷纷。`, interpretation: `这首诗写于明朝正统年间，当时官场盛行行贿送礼的风气，地方官员进京述职时总要带上土特产讨好权贵，加重百姓负担。于谦时任河南巡抚，进京时坚持不送礼，只带两袖清风，展现了一身正气。诗中'清风两袖'是最经典的名句，后来成了为官清廉的代名词。整首诗语言直白有力，像在和老百姓拉家常，却藏着堂堂正气，连后来乾隆皇帝都忍不住点赞抄录呢！` }] },
  { id: 658, title: "题酒店壁",
    author: "唐寅",
    dynasty: "明",
    category: "明",
    summary: "酒醒只在花前坐，酒醉还来花下眠，半醉半醒日复日，花落花开年复年，但愿老死花酒间，不愿鞠躬车马前",
    tags: "明,经典",
    color: "#ef4444",
    sections:[    { id: 1, title: "题酒店壁", original: `
桃花坞里桃花庵，
桃花庵下桃花仙，
桃花仙人种桃树，
又摘桃花换酒钱，
酒醒只在花前坐，
酒醉还来花下眠，
半醉半醒日复日，
花落花开年复年，
但愿老死花酒间，
不愿鞠躬车马前
`, translation: `在桃花坞里有一座桃花庵，桃花庵里住着一位桃花仙。桃花仙人种了好多桃树，又摘下桃花去换酒钱。酒醒后就坐在桃花前面，酒醉了就在桃花树下睡一觉。一天又一天，半醉半醒地过着；一年又一年，看着花开花落。只希望能在这花和酒中度过一生，不愿意弯着腰去巴结有钱有势的人。`, interpretation: `这首诗出自明代才子唐伯虎之手。当时他仕途不顺，灰心归乡，便在苏州桃花坞建了一座桃花庵，过起隐居生活。诗中最有趣的是他反复说"桃花"——桃花坞、桃花庵、桃花仙、桃花树，一口气用了六个"桃花"，看似啰嗦，却营造出一种满眼都是花、满心都是美的童话感。最后两句是全诗的灵魂：他宁愿在花丛中喝酒到老，也不愿弯着腰向权贵低头。这份傲气让唐伯虎成为后世最受欢迎的文人之一。` }] },
  { id: 659, title: "闲居",
    author: "李贽",
    dynasty: "明",
    category: "明",
    summary: "从今莫问人间事，篱下黄花晚节香，洗竹浇花春事足，安排樽酒送斜阳",
    tags: "明,写景",
    color: "#ef4444",
    sections:[    { id: 1, title: "闲居", original: `
从今莫问人间事，
篱下黄花晚节香，
洗竹浇花春事足，
安排樽酒送斜阳
`, translation: `从今以后，别再去过问人世间的那些烦心事了！你看，篱笆旁边的菊花正吐着晚秋的香气。给竹子洗个澡，给花儿浇浇水，春天该做的事就全做完了。再摆上一壶酒，慢慢送走西边那轮快要落山的太阳吧。`, interpretation: `李贽是明代一位特立独行的思想家，他不满官场的虚伪，辞官后归隐田园，这首诗就写于他闲居的时候。诗里最有意思的是菊花和竹子——菊花在秋天开放，古人说它象征着晚年的高洁品格；竹子呢，一年四季都青翠挺拔，代表着正直的骨气。李贽用“洗竹”“浇花”这种小小的日常事，告诉大家：真正的快乐不在追名逐利，而在亲手照料一草一木。最后那句“安排樽酒送斜阳”特别有味道，他不是悲伤地看落日，而是举起酒杯，悠哉悠哉地和夕阳告别，多洒脱呀！这首诗也让我们明白，再忙也要留一点时间给花草和好天气。` }] },
  { id: 660, title: "柳",
    author: "李渔",
    dynasty: "明",
    category: "明",
    summary: "近水遥山俱有情，垂垂万缕碧烟横，东君不惜黄金缕，散作人间柳絮轻",
    tags: "明,写景",
    color: "#ef4444",
    sections:[    { id: 1, title: "柳", original: `
近水遥山俱有情，
垂垂万缕碧烟横，
东君不惜黄金缕，
散作人间柳絮轻
`, translation: `近处的河水、远处的青山，都仿佛带着温柔的情意。
千万条低垂的柳枝，像一道横跨天空的青色烟雾。
春神毫不吝惜它那像黄金丝线般的嫩芽，
把它们轻轻撒向人间，变成了漫天飞舞的柳絮。`, interpretation: `这首诗写于明代，那时候的文人喜欢在山水之间寻找诗意。李渔是位很有生活情趣的文学家，他笔下的春天不孤单——山水有情，柳枝如烟。诗中最妙的是把春风比作一位慷慨的'东君'，把柳枝想成'黄金缕'，再变成轻盈的柳絮飞向人间，画面一下子就活了。这种把春天拟人化的写法，既亲切又浪漫。后来人们说起春天，总会想起'万缕碧烟'和飞舞的柳絮，这首诗功不可没呀！` }] },
  { id: 661, title: "四愁诗（节选）",
    author: "张衡",
    dynasty: "汉",
    category: "汉",
    summary: "我所思兮在太山，欲往从之梁父艰，美人赠我金错刀，何以报之英琼瑶",
    tags: "汉,经典",
    color: "#dc2626",
    sections:[    { id: 1, title: "四愁诗（节选）", original: `
我所思兮在太山，
欲往从之梁父艰，
侧身东望涕沾翰，
美人赠我金错刀，
何以报之英琼瑶，
路远莫致倚逍遥，
何为怀忧心烦劳
`, translation: `我思念的人啊在那巍峨的东泰山上，想去追随她，却被梁父山阻挡，前路艰难。侧过身向东眺望，思念的泪水沾湿了我的衣襟。美人送给我一把镀金的佩刀，我拿什么来回报她呢？只有光洁美丽的美玉。可路途太远，实在无法送到，只能怅惘地徘徊。为何满心忧愁，如此烦闷苦恼呢？`, interpretation: `这首诗是东汉科学家张衡写的，他不仅是发明地动仪的牛人，还很会写诗呢！那时候朝廷里小人当道，张衡满怀抱负却不得施展，于是把满腔忧愁寄托在这首诗里。他心里向往的"美人"，其实是理想和贤君的象征，可现实就像梁父山一样，挡住了去路。诗中最妙的就是用"金错刀"和"英琼瑶"来互相赠送，写出了知音难觅、理想难求的遗憾。"侧身东望涕沾翰"一句，伤心之情跃然纸上。这首诗开创了"四愁诗"的体例，后世很多人模仿它来写怀才不遇的愁绪。读起来一唱三叹，优美又让人心疼。` }] },
  { id: 662, title: "悲歌",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "悲歌可以当，泣远望可以，当归思念故，乡郁郁累累，欲归家无人，欲渡河无船，心思不能言，肠中车轮转",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "悲歌", original: `
悲歌可以当，
泣远望可以，
当归思念故，
乡郁郁累累，
欲归家无人，
欲渡河无船，
心思不能言，
肠中车轮转
`, translation: `想唱一首悲伤的歌来代替哭泣，我抬头向远方眺望，想用这眺望代替回乡。我心里头憋闷得满满的，真想回家啊，可家里却没有一个人在；想过河回家吧，河边又找不到渡船。这些心里的苦说不出，肠子里就像车轮骨碌碌地转，难受极了。`, interpretation: `这首诗来自汉代，是一位漂泊在外的游子写的，那时候很多人为了谋生离开家乡，常年回不了家。诗里最大的特点就是连用“当”字——“唱歌代替哭、望远代替回家”，这种说法叫“以……当……”，写出了游子想家却回不去、连哭都找不到方式的辛酸。最让人心疼的是“肠中车轮转”一句，肚子里的难受像车轮一样转个不停，比喻特别形象，把想家想得五脏六腑都在翻腾的那种感觉写活了。后来这句成了形容愁苦的经典说法，很多古诗里都化用过这种把心里苦写成身体痛的手法。` }] },
  { id: 663, title: "古歌",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "秋风萧萧愁杀出亦愁入亦愁座中何人谁不怀忧令我白头胡地多飚风树木何修修离家日趋远衣带日趋缓心思不能言肠中车轮转",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "古歌", original: `
秋风萧萧愁杀，
出亦愁，
入亦愁。
座中何人，
谁不怀忧？
令我白头。
胡地多飚风，
树木何修修。
离家日趋远，
衣带日趋缓。
心思不能言，
肠中车轮转
`, translation: `秋风呜呜地吹，愁啊愁！出门愁，进门也愁。座中在座的哪个人不心里发愁？愁得我头发都白了！北方胡地大风呼呼地刮，树木被吹得光秃秃的。离开家一天比一天远，身上的衣带一天比一天松（人一天比一天瘦）。心里的话说不出来，就像肠子里有车轮在转。`, interpretation: `这首《古歌》来自汉代，是一首在西北戍边的士兵唱出的思乡曲。汉朝与匈奴常年打仗，无数年轻人被征召到北方荒凉之地，一去就回不了家。诗中“秋风”“飚风”“修修的树木”，把边地的荒寒写得透透的；最妙的是“衣带日趋缓”一句，不说想念，却说腰带一天比一天松——人瘦了，可见愁有多深！结尾“肠中车轮转”更绝，思念像车轮在肚子里碾，说不出又停不下来。这种直白喊愁的写法，后来的乐府诗、《古诗十九首》都学它，连曹操的《短歌行》里那句“忧从中来，不可断绝”，也能看到它的影子。` }] },
  { id: 664, title: "枯鱼过河泣",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "枯鱼过河泣，何时悔复及，作书与鲂鱮，相教慎出入",
    tags: "汉,寓言",
    color: "#dc2626",
    sections:[    { id: 1, title: "枯鱼过河泣", original: `
枯鱼过河泣，
何时悔复及，
作书与鲂鱮，
相教慎出入
`, translation: `一条干死的鱼儿要过河，它呜呜地哭起来：现在后悔还来得及吗？它写信给鲂鱼和鱮鱼，劝告它们：进出河里一定要小心啊！`, interpretation: `这首汉代寓言诗写了一条枯鱼哭着警告同伴的故事。汉代乐府诗里有很多这样的动物寓言，借鱼之口讲人生道理。"枯鱼"是全诗最让人心疼的意象——它已经死了，却还在哭泣劝告朋友，原来它想用自己的惨痛经历告诉小伙伴：出去时要小心，别再重蹈覆辙。短短二十字，用拟人手法写得特别动人，连鱼都知道吸取教训，告诫朋友注意安全。"相教慎出入"这五个字成为千古名句，提醒人们做事要谨慎，别等吃了亏再后悔。` }] },
  { id: 665, title: "凛凛岁云暮",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "凛凛岁云暮，蝼蛄夕鸣悲，凉风率已厉，游子寒无衣",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "凛凛岁云暮", original: `
凛凛岁云暮，
蝼蛄夕鸣悲，
凉风率已厉，
游子寒无衣，
锦衾遗洛浦，
同袍与我违，
独宿累长夜，
梦想见容辉
`, translation: `寒冷的冬天又到了年底，蝼蛄在夜晚悲哀地叫着。冷风一阵比一阵猛烈，出门远行的人冷得没有衣服穿。洛水女神留下了华美的被子，当年一起发誓的伴侣也离开了我。独自一人度过了无数漫长的夜晚，只能在梦里看到你美丽的容颜。`, interpretation: `这首诗选自《古诗十九首》，写于东汉末年。那时候战乱频繁，很多人不得不离开家乡去远方谋生，亲人朋友天各一方。诗中最打动人的是'梦想见容辉'——因为太想念，只能在梦里见一面，多么心酸！诗人用了冬天、蝼蛄哀鸣、寒风这些冷清的事物，烘托出孤独凄凉的心情。'锦衾遗洛浦'用了一个典故：传说洛水女神宓妃留下锦被，让有情人梦魂相会，可诗人连这样的好运都没有，读来更让人鼻子发酸。这组《古诗十九首》被后人称为'五言之冠冕'，是中国最早成熟的五言诗，影响了曹植、陶渊明等大诗人，直到今天读起来依然让人感动。` }] },
  { id: 666, title: "驱车上东门",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "驱车上东门，遥望郭北墓，白杨何萧萧，松柏夹广路，下有陈死人，杳杳即长暮，人生忽如寄，寿无金石固，万岁更相送，圣贤莫能度",
    tags: "汉,哲理",
    color: "#dc2626",
    sections:[    { id: 1, title: "驱车上东门", original: `
驱车上东门，
遥望郭北墓，
白杨何萧萧，
松柏夹广路，
下有陈死人，
杳杳即长暮，
人生忽如寄，
寿无金石固，
万岁更相送，
圣贤莫能度
`, translation: `赶着车走上东城门，远远望见城北的坟墓。白杨树在风中沙沙作响，松树柏树夹在宽阔的大路两旁。坟墓里躺着早已死去的人，永远沉陷在无边的黑暗里。人的一生匆匆而过，像暂时寄居在世上，寿命哪有金属石头那样坚固。千年万代，人们一个接一个地离去送别彼此，就算是圣贤也没法超越死亡。`, interpretation: `这首诗来自汉代，是《古诗十九首》中的一首，属于汉末动荡岁月里的作品。那时候人们面对战乱和瘟疫，寿命普遍不长，所以诗人常常思考死亡。诗中最让人印象深刻的画面是城北的墓地上白杨萧萧、松柏森森，一阵风吹过，好像在提醒人世间有那么多沉睡的亡者。诗人用“人生忽如寄”把人生比作暂时借住的小旅店，多么形象又伤感！他还说寿命不如金石坚硬，就算是圣人也逃不过死亡。整首诗语言朴素却直击人心，那种对时光飞逝的感慨，至今读来还让人心头一紧。` }] },
  { id: 667, title: "去者日以疏",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "去者日以疏，来者日以亲，出郭门直视，但见丘与坟，古墓犁为田，松柏摧为薪，白杨多悲风，萧萧愁杀人",
    tags: "汉,感怀",
    color: "#dc2626",
    sections:[    { id: 1, title: "去者日以疏", original: `
去者日以疏，
来者日以亲，
出郭门直视，
但见丘与坟，
古墓犁为田，
松柏摧为薪，
白杨多悲风，
萧萧愁杀人，
思还故里闾，
欲归道无因
`, translation: `离去的人啊，一天比一天遥远；新来的人呢，一天比一天亲近。走出城门外举目远望，只看见大大小小的坟丘和坟墓。古老的坟墓被犁开变成了田地，墓边的松柏也被砍倒当成了柴火。白杨树在风中发出沙沙的声响，听得人心里愁苦极了。想回到从前住的街巷里，可是想回去也找不到路啊。`, interpretation: `这是一首《古诗十九首》里的诗，大约写于东汉末年。那时候战乱频繁、生死无常，人们对时光流逝格外敏感。诗人走出城门，看到的不是繁华，而是满眼的坟墓——曾经活生生的人，如今都化作了黄土，连坟头的松柏都被砍去烧柴了，多么让人心酸！最妙的是开头两句：'去者日以疏，来者日以亲'，说离开的人渐渐疏远，新认识的人慢慢亲近，其实谁都留不住，最后都会变成那座无名的坟。这首诗用朴素的句子写出了深刻的悲凉，被后人传诵了千年，成了中国诗歌里感叹人生无常的经典名句。` }] },
  { id: 668, title: "庭中有奇树",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "庭中有奇树，绿叶发华滋，攀条折其荣，将以遗所思，馨香盈怀袖，路远莫致之，此物何足贵，但感别经时",
    tags: "汉,情感",
    color: "#dc2626",
    sections:[    { id: 1, title: "庭中有奇树", original: `
庭中有奇树，
绿叶发华滋，
攀条折其荣，
将以遗所思，
馨香盈怀袖，
路远莫致之，
此物何足贵，
但感别经时
`, translation: `院子里有一棵特别的树，翠绿的叶子间开出了繁茂的花朵。我轻轻攀着枝条，摘下一朵盛开的花儿，想要送给心中思念的人。花儿的香气充满了我的衣襟和袖口，可惜路途太远，没法送到她面前。这花儿本身有什么珍贵的呢？只是分别得太久，让人心里十分思念。`, interpretation: `这首诗出自《古诗十九首》，是东汉末年文人的集体创作。那时候社会动荡，很多人背井离乡，亲友离散，所以这一时期的诗歌里特别多思念之情。诗中最动人的意象就是那棵院中开花的树——它没有写树的名字，只说“奇树”，让每棵树都可能是读者自家院中的那一棵，格外亲切。诗人折花想送，却因路远送不到，最后说“但感别经时”，把重点落在“别”字上。全诗短短八句，写出了思念的温柔、无奈与深沉。这种“托物寄情”的写法对后世影响很大，许多送别诗、思念诗都从中汲取灵感。` }] },
  { id: 669, title: "今日良宴会",
    author: "佚名",
    dynasty: "汉",
    category: "汉",
    summary: "人生寄一世，奄忽若飙尘，何不策高足，先据要路津，无为守穷贱，轗轲长苦辛",
    tags: "汉,哲理",
    color: "#dc2626",
    sections:[    { id: 1, title: "今日良宴会", original: `
今日良宴会，
欢乐难具陈，
人生寄一世，
奄忽若飙尘，
何不策高足，
先据要路津，
无为守穷贱，
轗轲长苦辛
`, translation: `今天有这么好的宴会，欢乐的事儿说也说不完。
人活一辈子，就像暂时寄居在世上，
忽然之间就像被狂风卷起的尘土。
为什么不扬起快马，加鞭飞驰，
先去抢占那重要的路口和渡口呢？
别干等着受穷受苦，
一辈子坎坷难走、又辛苦又辛酸！`, interpretation: `这首诗出自汉代《古诗十九首》，是东汉末年文人的心声。那时候社会动荡，很多人空有才华却没出路，心里又着急又迷茫。诗人用"飙尘"来形容人生——灰尘被风一吹就散啦，人活着也是转眼就过去的事儿，多可惜呀！所以他大喊：别傻等着受穷啦，赶紧去争去抢好位置！这种想法既真实又有点"心酸"，因为它说明很多人为了出人头地，连做人的淡定都不要了。这首诗最大的艺术特点就是"说大白话讲大道理"，不绕弯子，把心里话一股脑倒出来。后来"奄忽若飙尘"成了形容人生短暂的经典名句，连李白都偷偷学过它呢！` }] },
]
